diffs.replacement:
{
  "name": "PneuControl - Gestão de Manutenção de Pneus",
  "description": "Sistema intuitivo para controle de remessas, retornos e bônus de reforma de pneus, focado em eficiência e controle de frotas."
}

export enum ShipmentStatus {
  AWAITING = 'Aguardando Retorno',
  FINISHED = 'Finalizada'
}

export interface Shipment {
  id: string;
  number: string;
  sendDate: string;
  quantitySent: number;
  status: ShipmentStatus;
  returnDate?: string;
  returnDetails?: ReturnDetails;
}

export interface ReturnDetails {
  reformed: number;
  repaired: number;
  exchanged: number;
  failed: number; // Não deram reforma
}

export interface BonusStats {
  totalReformed: number;
  totalBonus: number;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Truck, 
  RotateCcw, 
  Plus, 
  BarChart3, 
  CheckCircle2, 
  Clock, 
  ChevronRight, 
  AlertCircle,
  Trophy,
  History,
  LayoutDashboard
} from 'lucide-react';
import { Shipment, ShipmentStatus, ReturnDetails, BonusStats } from './types';
import Dashboard from './components/Dashboard';
import ShipmentList from './components/ShipmentList';
import ShipmentForm from './components/ShipmentForm';
import ReturnForm from './components/ReturnForm';
import BonusNotification from './components/BonusNotification';

const STORAGE_KEY = 'pneucontrol_data';

const App: React.FC = () => {
  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [view, setView] = useState<'dashboard' | 'new' | 'list' | 'return'>('dashboard');
  const [activeShipmentId, setActiveShipmentId] = useState<string | null>(null);
  const [showBonusAlert, setShowBonusAlert] = useState(false);
  const [bonusCount, setBonusCount] = useState(0);

  // Initialize data from LocalStorage
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setShipments(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse local storage", e);
      }
    }
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(shipments));
  }, [shipments]);

  // Derived Stats
  const stats = useMemo(() => {
    const totalReformed = shipments.reduce((acc, s) => acc + (s.returnDetails?.reformed || 0), 0);
    const totalBonus = Math.floor(totalReformed / 15);
    return { totalReformed, totalBonus };
  }, [shipments]);

  // Bonus Notification Logic
  useEffect(() => {
    if (stats.totalBonus > bonusCount) {
      if (bonusCount > 0 || stats.totalBonus === 1) { // Alert when a new milestone is hit
        setShowBonusAlert(true);
      }
      setBonusCount(stats.totalBonus);
    }
  }, [stats.totalBonus, bonusCount]);

  const handleAddShipment = (data: { date: string, quantity: number }) => {
    const newShipment: Shipment = {
      id: crypto.randomUUID(),
      number: `REM-${String(shipments.length + 1).padStart(4, '0')}`,
      sendDate: data.date,
      quantitySent: data.quantity,
      status: ShipmentStatus.AWAITING
    };
    setShipments([newShipment, ...shipments]);
    setView('dashboard');
  };

  const handleRegisterReturn = (id: string, details: ReturnDetails, date: string) => {
    setShipments(prev => prev.map(s => {
      if (s.id === id) {
        return {
          ...s,
          status: ShipmentStatus.FINISHED,
          returnDate: date,
          returnDetails: details
        };
      }
      return s;
    }));
    setView('dashboard');
  };

  const openReturnForm = (id: string) => {
    setActiveShipmentId(id);
    setView('return');
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-20 md:pb-0">
      {/* Header */}
      <header className="bg-blue-700 text-white p-4 shadow-lg sticky top-0 z-10">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Truck className="w-8 h-8" />
            <h1 className="text-xl font-bold tracking-tight">PneuControl</h1>
          </div>
          <div className="text-sm font-medium bg-blue-600 px-3 py-1 rounded-full flex items-center gap-2">
            <Trophy className="w-4 h-4 text-yellow-400" />
            {stats.totalBonus} Bônus
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-4xl w-full mx-auto p-4 animate-in fade-in duration-500">
        {view === 'dashboard' && (
          <Dashboard 
            stats={stats} 
            onNewShipment={() => setView('new')} 
            onViewList={() => setView('list')}
            recentShipments={shipments.slice(0, 5)}
            onOpenReturn={openReturnForm}
          />
        )}

        {view === 'new' && (
          <ShipmentForm 
            onSave={handleAddShipment} 
            onCancel={() => setView('dashboard')} 
          />
        )}

        {view === 'list' && (
          <ShipmentList 
            shipments={shipments} 
            onOpenReturn={openReturnForm}
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={shipments.find(s => s.id === activeShipmentId)!}
            onSave={(details, date) => handleRegisterReturn(activeShipmentId, details, date)}
            onCancel={() => setView('dashboard')}
          />
        )}
      </main>

      {/* Bottom Navigation (Mobile Only) */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-2 md:hidden flex justify-around items-center z-10">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-xs">Início</span>
        </button>
        <button 
          onClick={() => setView('new')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'new' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <div className="bg-blue-600 text-white p-2 rounded-full -mt-8 shadow-lg ring-4 ring-slate-50">
            <Plus className="w-6 h-6" />
          </div>
          <span className="text-xs mt-1">Nova</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'list' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <History className="w-6 h-6" />
          <span className="text-xs">Histórico</span>
        </button>
      </nav>

      {/* Notifications */}
      {showBonusAlert && (
        <BonusNotification 
          count={stats.totalBonus} 
          onClose={() => setShowBonusAlert(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { BarChart3, Trophy, Timer, Plus, ArrowRight, Clock, CheckCircle2 } from 'lucide-react';
import { BonusStats, Shipment, ShipmentStatus } from '../types';

interface DashboardProps {
  stats: BonusStats;
  onNewShipment: () => void;
  onViewList: () => void;
  recentShipments: Shipment[];
  onOpenReturn: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, onNewShipment, onViewList, recentShipments, onOpenReturn }) => {
  const nextBonusProgress = stats.totalReformed % 15;
  const progressPercent = (nextBonusProgress / 15) * 100;

  return (
    <div className="space-y-6">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="bg-blue-100 p-3 rounded-xl text-blue-600">
            <BarChart3 className="w-6 h-6" />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Total Reformas</p>
            <p className="text-2xl font-bold">{stats.totalReformed}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="bg-yellow-100 p-3 rounded-xl text-yellow-600">
            <Trophy className="w-6 h-6" />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Bônus Gerados</p>
            <p className="text-2xl font-bold">{stats.totalBonus}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-center">
          <div className="flex justify-between items-end mb-2">
            <p className="text-sm text-slate-500 font-medium">Próximo Bônus</p>
            <p className="text-xs font-bold text-blue-600">{nextBonusProgress}/15</p>
          </div>
          <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
            <div 
              className="bg-blue-600 h-full rounded-full transition-all duration-1000 ease-out"
              style={{ width: `${progressPercent}%` }}
            ></div>
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="flex gap-4">
        <button 
          onClick={onNewShipment}
          className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 px-6 rounded-2xl shadow-md transition-all flex items-center justify-center gap-2 text-lg active:scale-95"
        >
          <Plus className="w-6 h-6" />
          Nova Remessa
        </button>
      </div>

      {/* Recent Activity */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-50 flex justify-between items-center">
          <h2 className="font-bold text-slate-700">Últimas Remessas</h2>
          <button 
            onClick={onViewList}
            className="text-blue-600 text-sm font-semibold flex items-center gap-1 hover:underline"
          >
            Ver todas <ArrowRight className="w-4 h-4" />
          </button>
        </div>

        {recentShipments.length === 0 ? (
          <div className="p-10 text-center text-slate-400">
            <Truck className="w-12 h-12 mx-auto mb-2 opacity-20" />
            <p>Nenhuma remessa encontrada.</p>
          </div>
        ) : (
          <div className="divide-y divide-slate-50">
            {recentShipments.map((shipment) => (
              <div key={shipment.id} className="p-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-full ${shipment.status === ShipmentStatus.AWAITING ? 'bg-orange-100 text-orange-600' : 'bg-green-100 text-green-600'}`}>
                    {shipment.status === ShipmentStatus.AWAITING ? <Clock className="w-5 h-5" /> : <CheckCircle2 className="w-5 h-5" />}
                  </div>
                  <div>
                    <p className="font-bold text-slate-800">{shipment.number}</p>
                    <p className="text-xs text-slate-500">{new Date(shipment.sendDate).toLocaleDateString()}</p>
                  </div>
                </div>

                <div className="flex items-center gap-4">
                  <div className="text-right hidden sm:block">
                    <p className="text-sm font-semibold text-slate-700">{shipment.quantitySent} pneus</p>
                    <p className={`text-xs ${shipment.status === ShipmentStatus.AWAITING ? 'text-orange-500' : 'text-green-500'}`}>
                      {shipment.status}
                    </p>
                  </div>
                  {shipment.status === ShipmentStatus.AWAITING && (
                    <button 
                      onClick={() => onOpenReturn(shipment.id)}
                      className="bg-slate-100 hover:bg-slate-200 text-slate-700 p-2 rounded-xl transition-colors active:scale-95"
                    >
                      <RotateCcw className="w-5 h-5" />
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { X, Calendar, Hash } from 'lucide-react';

interface ShipmentFormProps {
  onSave: (data: { date: string, quantity: number }) => void;
  onCancel: () => void;
}

const ShipmentForm: React.FC<ShipmentFormProps> = ({ onSave, onCancel }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [quantity, setQuantity] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!date || !quantity || parseInt(quantity) <= 0) {
      alert("Por favor, preencha todos os campos corretamente.");
      return;
    }
    onSave({ date, quantity: parseInt(quantity) });
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden animate-in slide-in-from-bottom duration-300">
      <div className="bg-blue-700 text-white p-4 flex justify-between items-center">
        <h2 className="text-lg font-bold">Nova Remessa</h2>
        <button onClick={onCancel} className="p-1 hover:bg-blue-600 rounded-full transition-colors">
          <X className="w-6 h-6" />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">
        <div>
          <label className="block text-sm font-bold text-slate-700 mb-2 flex items-center gap-2">
            <Calendar className="w-4 h-4 text-blue-600" />
            Data da Remessa
          </label>
          <input 
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-4 text-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all outline-none"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-bold text-slate-700 mb-2 flex items-center gap-2">
            <Hash className="w-4 h-4 text-blue-600" />
            Quantidade Total de Pneus
          </label>
          <input 
            type="number"
            inputMode="numeric"
            placeholder="Ex: 20"
            value={quantity}
            onChange={(e) => setQuantity(e.target.value)}
            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-4 text-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all outline-none"
            min="1"
            required
          />
        </div>

        <div className="pt-4 flex gap-3">
          <button 
            type="button"
            onClick={onCancel}
            className="flex-1 bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-4 rounded-xl transition-all"
          >
            Cancelar
          </button>
          <button 
            type="submit"
            className="flex-[2] bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-blue-200 transition-all"
          >
            Cadastrar Remessa
          </button>
        </div>
      </form>
    </div>
  );
};

export default ShipmentForm;

import React, { useState, useMemo } from 'react';
import { X, Save, AlertCircle } from 'lucide-react';
import { Shipment, ReturnDetails } from '../types';

interface ReturnFormProps {
  shipment: Shipment;
  onSave: (details: ReturnDetails, date: string) => void;
  onCancel: () => void;
}

const ReturnForm: React.FC<ReturnFormProps> = ({ shipment, onSave, onCancel }) => {
  const [reformed, setReformed] = useState(0);
  const [repaired, setRepaired] = useState(0);
  const [exchanged, setExchanged] = useState(0);
  const [failed, setFailed] = useState(0);
  const [returnDate, setReturnDate] = useState(new Date().toISOString().split('T')[0]);

  const currentTotal = useMemo(() => {
    return reformed + repaired + exchanged + failed;
  }, [reformed, repaired, exchanged, failed]);

  const remaining = shipment.quantitySent - currentTotal;
  const isMatch = currentTotal === shipment.quantitySent;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isMatch) {
      alert(`A soma dos pneus (${currentTotal}) deve ser exatamente igual à quantidade enviada (${shipment.quantitySent}).`);
      return;
    }
    onSave({ reformed, repaired, exchanged, failed }, returnDate);
  };

  const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
    e.target.select();
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden animate-in zoom-in-95 duration-200">
      <div className="bg-slate-800 text-white p-4 flex justify-between items-center">
        <div>
          <h2 className="text-lg font-bold">Registrar Retorno</h2>
          <p className="text-xs text-slate-400">Referente a {shipment.number}</p>
        </div>
        <button onClick={onCancel} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
          <X className="w-6 h-6" />
        </button>
      </div>

      <div className="bg-blue-50 p-4 border-b border-blue-100 flex justify-between items-center">
        <span className="text-sm font-semibold text-blue-800 uppercase tracking-wider">Total Enviado</span>
        <span className="text-2xl font-black text-blue-900">{shipment.quantitySent}</span>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-5">
        <div>
          <label className="block text-sm font-bold text-slate-600 mb-1">Data de Retorno</label>
          <input 
            type="date"
            value={returnDate}
            onChange={(e) => setReturnDate(e.target.value)}
            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 focus:ring-2 focus:ring-slate-500 outline-none"
            required
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="block text-xs font-bold text-green-700">REFORMADOS</label>
            <input 
              type="number"
              min="0"
              value={reformed}
              onFocus={handleFocus}
              onChange={(e) => setReformed(Math.max(0, parseInt(e.target.value) || 0))}
              className="w-full bg-slate-50 border border-green-100 rounded-xl p-3 text-lg font-bold text-green-700 focus:ring-2 focus:ring-green-500 outline-none"
            />
          </div>
          <div className="space-y-1">
            <label className="block text-xs font-bold text-blue-700">CONSERTADOS</label>
            <input 
              type="number"
              min="0"
              value={repaired}
              onFocus={handleFocus}
              onChange={(e) => setRepaired(Math.max(0, parseInt(e.target.value) || 0))}
              className="w-full bg-slate-50 border border-blue-100 rounded-xl p-3 text-lg font-bold text-blue-700 focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>
          <div className="space-y-1">
            <label className="block text-xs font-bold text-purple-700">TROCADOS</label>
            <input 
              type="number"
              min="0"
              value={exchanged}
              onFocus={handleFocus}
              onChange={(e) => setExchanged(Math.max(0, parseInt(e.target.value) || 0))}
              className="w-full bg-slate-50 border border-purple-100 rounded-xl p-3 text-lg font-bold text-purple-700 focus:ring-2 focus:ring-purple-500 outline-none"
            />
          </div>
          <div className="space-y-1">
            <label className="block text-xs font-bold text-red-700">SEM REFORMA</label>
            <input 
              type="number"
              min="0"
              value={failed}
              onFocus={handleFocus}
              onChange={(e) => setFailed(Math.max(0, parseInt(e.target.value) || 0))}
              className="w-full bg-slate-50 border border-red-100 rounded-xl p-3 text-lg font-bold text-red-700 focus:ring-2 focus:ring-red-500 outline-none"
            />
          </div>
        </div>

        <div className={`p-4 rounded-xl flex items-center justify-between transition-colors ${isMatch ? 'bg-green-100 text-green-800' : 'bg-orange-100 text-orange-800'}`}>
          <div className="flex items-center gap-2">
            {!isMatch && <AlertCircle className="w-5 h-5 animate-pulse" />}
            <span className="text-sm font-bold">Total Preenchido: {currentTotal}</span>
          </div>
          {!isMatch && (
            <span className="text-xs font-bold uppercase">Faltam: {remaining}</span>
          )}
          {isMatch && (
            <span className="text-xs font-bold uppercase">Números OK!</span>
          )}
        </div>

        <button 
          type="submit"
          disabled={!isMatch}
          className={`w-full font-bold py-4 rounded-xl shadow-lg flex items-center justify-center gap-2 transition-all ${
            isMatch 
              ? 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-200' 
              : 'bg-slate-200 text-slate-400 cursor-not-allowed'
          }`}
        >
          <Save className="w-5 h-5" />
          Finalizar Remessa
        </button>
      </form>
    </div>
  );
};

export default ReturnForm;

import React from 'react';
import { ChevronLeft, RotateCcw, Clock, CheckCircle2, History } from 'lucide-react';
import { Shipment, ShipmentStatus } from '../types';

interface ShipmentListProps {
  shipments: Shipment[];
  onOpenReturn: (id: string) => void;
  onBack: () => void;
}

const ShipmentList: React.FC<ShipmentListProps> = ({ shipments, onOpenReturn, onBack }) => {
  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4 mb-2">
        <button 
          onClick={onBack}
          className="p-2 hover:bg-slate-200 rounded-full transition-colors"
        >
          <ChevronLeft className="w-6 h-6 text-slate-600" />
        </button>
        <h2 className="text-xl font-bold text-slate-700">Histórico Completo</h2>
      </div>

      {shipments.length === 0 ? (
        <div className="bg-white rounded-2xl p-12 text-center text-slate-400 shadow-sm border border-slate-100">
          <History className="w-16 h-16 mx-auto mb-4 opacity-10" />
          <p className="text-lg">Nenhuma remessa registrada ainda.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {shipments.map((s) => (
            <div key={s.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex justify-between items-start mb-3">
                <div className="flex items-center gap-2">
                  <div className={`w-3 h-3 rounded-full ${s.status === ShipmentStatus.AWAITING ? 'bg-orange-400' : 'bg-green-500'}`}></div>
                  <span className="text-xs font-bold uppercase text-slate-400">{s.status}</span>
                </div>
                <span className="text-xs font-medium text-slate-400">Enviado em {new Date(s.sendDate).toLocaleDateString()}</span>
              </div>

              <div className="flex justify-between items-end">
                <div>
                  <h3 className="text-lg font-black text-slate-800">{s.number}</h3>
                  <p className="text-sm font-semibold text-slate-500">{s.quantitySent} Pneus no total</p>
                </div>

                {s.status === ShipmentStatus.AWAITING ? (
                  <button 
                    onClick={() => onOpenReturn(s.id)}
                    className="bg-blue-600 hover:bg-blue-700 text-white font-bold px-4 py-2 rounded-xl flex items-center gap-2 text-sm shadow-md active:scale-95 transition-all"
                  >
                    <RotateCcw className="w-4 h-4" />
                    Retornar
                  </button>
                ) : (
                  <div className="text-right">
                    <p className="text-xs font-bold text-slate-400">Retorno: {s.returnDate ? new Date(s.returnDate).toLocaleDateString() : '-'}</p>
                    <div className="flex gap-2 mt-1">
                      <span className="bg-green-50 text-green-700 text-[10px] px-1.5 py-0.5 rounded font-bold">R:{s.returnDetails?.reformed}</span>
