import React, { useState, useEffect, useMemo } from 'react';
import { 
  Truck, 
  RotateCcw, 
  Plus, 
  BarChart3, 
  CheckCircle2, 
  Clock, 
  ChevronRight, 
  AlertCircle,
  Trophy,
  History,
  LayoutDashboard,
  LogOut,
  User as UserIcon
} from 'lucide-react';
import { Shipment, ShipmentStatus, ReturnDetails, BonusStats } from './types';
import Dashboard from './components/Dashboard';
import ShipmentList from './components/ShipmentList';
import ShipmentForm from './components/ShipmentForm';
import ReturnForm from './components/ReturnForm';
import BonusNotification from './components/BonusNotification';
import Login from './components/Login';

const STORAGE_KEY = 'pneucontrol_data';
const AUTH_KEY = 'pneucontrol_user';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<string | null>(null);
  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [view, setView] = useState<'dashboard' | 'new' | 'list' | 'return'>('dashboard');
  const [activeShipmentId, setActiveShipmentId] = useState<string | null>(null);
  const [showBonusAlert, setShowBonusAlert] = useState(false);
  const [bonusCount, setBonusCount] = useState(0);

  // Initialize data and Auth from LocalStorage
  useEffect(() => {
    const savedUser = localStorage.getItem(AUTH_KEY);
    if (savedUser) setCurrentUser(savedUser);

    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        setShipments(JSON.parse(savedData));
      } catch (e) {
        console.error("Failed to parse local storage", e);
      }
    }
  }, []);

  // Save data to LocalStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(shipments));
  }, [shipments]);

  // Derived Stats
  const stats = useMemo(() => {
    const totalReformed = shipments.reduce((acc, s) => acc + (s.returnDetails?.reformed || 0), 0);
    const totalBonus = Math.floor(totalReformed / 15);
    return { totalReformed, totalBonus };
  }, [shipments]);

  // Bonus Notification Logic
  useEffect(() => {
    if (stats.totalBonus > bonusCount) {
      if (bonusCount > 0 || stats.totalBonus === 1) { 
        setShowBonusAlert(true);
      }
      setBonusCount(stats.totalBonus);
    }
  }, [stats.totalBonus, bonusCount]);

  const handleLogin = (username: string) => {
    setCurrentUser(username);
    localStorage.setItem(AUTH_KEY, username);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_KEY);
    setView('dashboard');
  };

  const handleAddShipment = (data: { date: string, quantity: number }) => {
    const newShipment: Shipment = {
      id: crypto.randomUUID(),
      number: `REM-${String(shipments.length + 1).padStart(4, '0')}`,
      sendDate: data.date,
      quantitySent: data.quantity,
      status: ShipmentStatus.AWAITING
    };
    setShipments([newShipment, ...shipments]);
    setView('dashboard');
  };

  const handleRegisterReturn = (id: string, details: ReturnDetails, date: string) => {
    setShipments(prev => prev.map(s => {
      if (s.id === id) {
        return {
          ...s,
          status: ShipmentStatus.FINISHED,
          returnDate: date,
          returnDetails: details
        };
      }
      return s;
    }));
    setView('dashboard');
  };

  const openReturnForm = (id: string) => {
    setActiveShipmentId(id);
    setView('return');
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-20 md:pb-0">
      {/* Header */}
      <header className="bg-blue-700 text-white p-4 shadow-lg sticky top-0 z-10">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Truck className="w-7 h-7" />
            <h1 className="text-xl font-bold tracking-tight">PneuControl</h1>
          </div>

          <div className="flex items-center gap-3">
            <div className="hidden sm:flex items-center gap-2 text-xs font-medium bg-blue-800/50 px-3 py-1.5 rounded-full border border-blue-400/20">
              <UserIcon className="w-3 h-3" />
              {currentUser}
            </div>
            <div className="text-xs font-bold bg-yellow-500 text-blue-900 px-3 py-1.5 rounded-full flex items-center gap-2 shadow-inner">
              <Trophy className="w-3 h-3" />
              {stats.totalBonus} Bônus
            </div>
            <button 
              onClick={handleLogout}
              className="p-2 hover:bg-blue-600 rounded-full transition-colors text-blue-100"
              title="Sair"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-4xl w-full mx-auto p-4 animate-in fade-in duration-500">
        {view === 'dashboard' && (
          <Dashboard 
            stats={stats} 
            onNewShipment={() => setView('new')} 
            onViewList={() => setView('list')}
            recentShipments={shipments.slice(0, 5)}
            onOpenReturn={openReturnForm}
          />
        )}

        {view === 'new' && (
          <ShipmentForm 
            onSave={handleAddShipment} 
            onCancel={() => setView('dashboard')} 
          />
        )}

        {view === 'list' && (
          <ShipmentList 
            shipments={shipments} 
            onOpenReturn={openReturnForm}
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={shipments.find(s => s.id === activeShipmentId)!}
            onSave={(details, date) => handleRegisterReturn(activeShipmentId, details, date)}
            onCancel={() => setView('dashboard')}
          />
        )}
      </main>

      {/* Bottom Navigation (Mobile Only) */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-2 md:hidden flex justify-around items-center z-10">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-xs">Início</span>
        </button>
        <button 
          onClick={() => setView('new')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'new' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <div className="bg-blue-600 text-white p-2 rounded-full -mt-8 shadow-lg ring-4 ring-slate-50">
            <Plus className="w-6 h-6" />
          </div>
          <span className="text-xs mt-1">Nova</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'list' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <History className="w-6 h-6" />
          <span className="text-xs">Histórico</span>
        </button>
      </nav>

      {/* Notifications */}
      {showBonusAlert && (
        <BonusNotification 
          count={stats.totalBonus} 
          onClose={() => setShowBonusAlert(false)} 
        />
      )}
    </div>
  );
};

export default App;

