          onClick={onNewShipment}
          className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 px-6 rounded-2xl shadow-md transition-all flex items-center justify-center gap-2 text-lg active:scale-95"
        >
          <Plus className="w-6 h-6" />
          Nova Remessa
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-50 flex justify-between items-center">
          <h2 className="font-bold text-slate-700">Últimas Remessas</h2>
          <button 
            onClick={onViewList}
            className="text-blue-600 text-sm font-semibold flex items-center gap-1 hover:underline"
          >
            Ver todas <ArrowRight className="w-4 h-4" />
          </button>
        </div>

        {recentShipments.length === 0 ? (
          <div className="p-10 text-center text-slate-400">
            <Truck className="w-12 h-12 mx-auto mb-2 opacity-20" />
            <p>Nenhuma remessa encontrada.</p>
          </div>
        ) : (
          <div className="divide-y divide-slate-50">
            {recentShipments.map((shipment) => {
               const totalReturned = shipment.returns.reduce((sum, r) => sum + r.reformed + r.repaired + r.exchanged + r.failed, 0);

               // Definindo cores e ícones baseados no status
               let statusStyles = "bg-red-100 text-red-600";
               let StatusIcon = AlertCircle;

               if (shipment.status === ShipmentStatus.PARTIAL) {
                 statusStyles = "bg-yellow-100 text-yellow-600";
                 StatusIcon = Clock;
               } else if (shipment.status === ShipmentStatus.FINISHED) {
                 statusStyles = "bg-green-100 text-green-600";
                 StatusIcon = CheckCircle2;
               }

               return (
                <div key={shipment.id} className="p-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-full ${statusStyles}`}>
                      <StatusIcon className="w-5 h-5" />
                    </div>
                    <div>
                      <p className="font-bold text-slate-800">{shipment.number}</p>
                      <p className="text-xs text-slate-500">{new Date(shipment.sendDate).toLocaleDateString()}</p>
                    </div>
                  </div>

                  <div className="flex items-center gap-4">
                    <div className="text-right hidden sm:block">
                      <p className="text-sm font-semibold text-slate-700">{totalReturned} / {shipment.quantitySent} pneus</p>
                      <p className={`text-xs font-bold ${
                        shipment.status === ShipmentStatus.AWAITING ? 'text-red-500' : 
                        shipment.status === ShipmentStatus.PARTIAL ? 'text-yellow-600' : 'text-green-500'
                      }`}>
                        {shipment.status}
                      </p>
                    </div>
                    {shipment.status !== ShipmentStatus.FINISHED && (
                      <button 
                        onClick={() => onOpenReturn(shipment.id)}
                        className="bg-slate-100 hover:bg-slate-200 text-slate-700 p-2 rounded-xl transition-colors active:scale-95"
                      >
                        <RotateCcw className="w-5 h-5" />
                      </button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { ChevronLeft, RotateCcw, Clock, CheckCircle2, History, ChevronDown, ChevronUp, FileText, Gift, AlertCircle } from 'lucide-react';
import { Shipment, ShipmentStatus } from '../types';

interface ShipmentListProps {
  shipments: Shipment[];
  onOpenReturn: (id: string) => void;
  onBack: () => void;
}

const ShipmentList: React.FC<ShipmentListProps> = ({ shipments, onOpenReturn, onBack }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4 mb-2">
        <button 
          onClick={onBack}
          className="p-2 hover:bg-slate-200 rounded-full transition-colors"
        >
          <ChevronLeft className="w-6 h-6 text-slate-600" />
        </button>
        <h2 className="text-xl font-bold text-slate-700">Histórico de Remessas</h2>
      </div>

      {shipments.length === 0 ? (
        <div className="bg-white rounded-2xl p-12 text-center text-slate-400 shadow-sm border border-slate-100">
          <History className="w-16 h-16 mx-auto mb-4 opacity-10" />
          <p className="text-lg">Nenhuma remessa registrada ainda.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {shipments.map((s) => {
            const totalReturned = s.returns.reduce((sum, r) => sum + r.reformed + r.repaired + r.exchanged + r.failed, 0);
            const isExpanded = expandedId === s.id;
            const progressPercent = (totalReturned / s.quantitySent) * 100;

            // Definindo as cores das bolinhas de status
            let dotColor = "bg-red-500";
            let statusTextColor = "text-red-500";

            if (s.status === ShipmentStatus.PARTIAL) {
              dotColor = "bg-yellow-400";
              statusTextColor = "text-yellow-600";
            } else if (s.status === ShipmentStatus.FINISHED) {
              dotColor = "bg-green-500";
              statusTextColor = "text-green-500";
            }

            return (
              <div key={s.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="p-4" onClick={() => toggleExpand(s.id)}>
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex items-center gap-2">
                      <div className={`w-3 h-3 rounded-full ${dotColor}`}></div>
                      <span className={`text-[10px] font-black uppercase ${statusTextColor}`}>{s.status}</span>
                    </div>
                    <span className="text-xs font-medium text-slate-400">{new Date(s.sendDate).toLocaleDateString()}</span>
                  </div>

                  <div className="flex justify-between items-center">
                    <div>
                      <h3 className="text-lg font-black text-slate-800 leading-tight">{s.number}</h3>
                      <p className="text-sm font-bold text-slate-500">{totalReturned} / {s.quantitySent} Pneus</p>
                    </div>

                    <div className="flex items-center gap-2">
                      {s.status !== ShipmentStatus.FINISHED && (
                        <button 
                          onClick={(e) => { e.stopPropagation(); onOpenReturn(s.id); }}
                          className="bg-blue-600 hover:bg-blue-700 text-white p-2 rounded-xl shadow-md active:scale-95 transition-all"
                        >
                          <RotateCcw className="w-5 h-5" />
                        </button>
                      )}
                      <div className="p-1 text-slate-400">
                        {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                      </div>
                    </div>
                  </div>

                  <div className="mt-3 w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                    <div 
                      className={`h-full rounded-full transition-all duration-500 ${
                        s.status === ShipmentStatus.FINISHED ? 'bg-green-500' : 
                        s.status === ShipmentStatus.PARTIAL ? 'bg-yellow-400' : 'bg-red-500'
                      }`}
                      style={{ width: `${progressPercent}%` }}
                    ></div>
                  </div>
                </div>

                {isExpanded && s.returns.length > 0 && (
                  <div className="bg-slate-50 p-4 border-t border-slate-100 space-y-3 animate-in slide-in-from-top-2 duration-200">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Retornos Registrados</h4>
                    {s.returns.map((r, idx) => (
                      <div key={r.id} className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm">
                        <div className="flex justify-between items-center mb-2 border-b border-slate-50 pb-2">
                          <div className="flex items-center gap-2">
                            <FileText className="w-3 h-3 text-blue-500" />
                            <span className="text-xs font-bold text-slate-700">{r.invoiceNumber}</span>
                            {r.bonusUsed && (
                                <span className="bg-yellow-100 text-yellow-700 text-[8px] font-black px-1.5 py-0.5 rounded-full flex items-center gap-0.5 uppercase">
                                    <Gift className="w-2 h-2" /> Bônus Utilizado
                                </span>
                            )}
                          </div>
                          <span className="text-[10px] font-medium text-slate-400">{new Date(r.date).toLocaleDateString()}</span>
                        </div>
                        <div className="grid grid-cols-4 gap-1 text-center">
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 uppercase">Ref</p>
                            <p className="text-sm font-bold text-green-600">{r.reformed}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 uppercase">Cons</p>
                            <p className="text-sm font-bold text-blue-600">{r.repaired}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 uppercase">Troc</p>
                            <p className="text-sm font-bold text-purple-600">{r.exchanged}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 uppercase">S/R</p>
                            <p className="text-sm font-bold text-red-600">{r.failed}</p>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default ShipmentList;

