Para integrar o aplicativo com o Google Sheets, você deve criar um novo projeto no [Google Apps Script](https://script.google.com/) e colar o seguinte código:

```javascript
/**
 * Script para integração do Controle de Reformas com Google Sheets
 * 1. Crie uma nova Planilha Google.
 * 2. Vá em Extensões > Apps Script.
 * 3. Cole este código e salve.
 * 4. Clique em Implantar > Nova implantação.
 * 5. Selecione "App da Web" e permita acesso a "Qualquer pessoa".
 */

function doPost(e) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName("Remessas") || ss.insertSheet("Remessas");

    // Configura cabeçalho se a planilha estiver vazia
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(["ID", "Número", "Data Envio", "Quantidade", "Status", "Retornos JSON", "Última Atualização"]);
    }

    const data = JSON.parse(e.postData.contents);
    const shipments = data.shipments;

    // Limpa dados antigos para atualizar com o estado atual (opcional)
    // Se preferir log de transações, pode apenas dar appendRow
    sheet.clear();
    sheet.appendRow(["ID", "Número", "Data Envio", "Quantidade", "Status", "Retornos JSON", "Última Atualização"]);

    shipments.forEach(s => {
      sheet.appendRow([
        s.id,
        s.number,
        s.sendDate,
        s.quantitySent,
        s.status,
        JSON.stringify(s.returns),
        new Date()
      ]);
    });

    return ContentService.createTextOutput(JSON.stringify({ "status": "success", "count": shipments.length }))
      .setMimeType(ContentService.MimeType.JSON);
  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ "status": "error", "message": err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}
