import React, { useState, useEffect, useMemo } from 'react';
import { 
  Disc, 
  RotateCcw, 
  Plus, 
  BarChart3, 
  CheckCircle2, 
  Clock, 
  ChevronRight, 
  AlertCircle,
  Trophy,
  History,
  LayoutDashboard,
  LogOut,
  User as UserIcon,
  PieChart,
  Gift,
  CloudUpload
} from 'lucide-react';
import { Shipment, ShipmentStatus, ReturnEvent, BonusStats } from './types';
import Dashboard from './components/Dashboard';
import ShipmentList from './components/ShipmentList';
import ShipmentForm from './components/ShipmentForm';
import ReturnForm from './components/ReturnForm';
import BonusNotification from './components/BonusNotification';
import Login from './components/Login';

const STORAGE_KEY = 'pneucontrol_data_v3';
const AUTH_KEY = 'pneucontrol_user';
const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbwi-YwN4a8TuVIt3fV1Ujyk20JgwU6vn0zen2ojg4S4RimfW_5ep7nuX4a4kt8IRbo/exec';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<string | null>(null);
  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [view, setView] = useState<'dashboard' | 'new' | 'list' | 'return'>('dashboard');
  const [activeShipmentId, setActiveShipmentId] = useState<string | null>(null);
  const [showBonusAlert, setShowBonusAlert] = useState(false);
  const [lastBonusCount, setLastBonusCount] = useState(0);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    const savedUser = localStorage.getItem(AUTH_KEY);
    if (savedUser) setCurrentUser(savedUser);

    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        setShipments(parsed);
      } catch (e) {
        console.error("Failed to parse local storage", e);
      }
    }
  }, []);

  // Sincronização com LocalStorage e Google Sheets
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(shipments));

    const syncWithSheets = async () => {
      if (shipments.length === 0) return;
      setIsSyncing(true);
      try {
        // Usando no-cors para evitar problemas de redirecionamento do Google Apps Script
        await fetch(GOOGLE_SCRIPT_URL, {
          method: 'POST',
          mode: 'no-cors',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ shipments }),
        });
      } catch (error) {
        console.error("Erro ao sincronizar com Google Sheets:", error);
      } finally {
        // Pequeno delay para feedback visual
        setTimeout(() => setIsSyncing(false), 1000);
      }
    };

    const timeoutId = setTimeout(syncWithSheets, 2000); // Debounce de 2 segundos para não sobrecarregar
    return () => clearTimeout(timeoutId);
  }, [shipments]);

  const stats: BonusStats = useMemo(() => {
    let totalReformed = 0;
    let totalBonusPaid = 0;

    shipments.forEach(s => {
      s.returns.forEach(r => {
        totalReformed += r.reformed;
        if (r.bonusUsed) {
          totalBonusPaid += 1;
        }
      });
    });

    const totalBonusEarned = Math.floor(totalReformed / 15);
    const pendingBonuses = Math.max(0, totalBonusEarned - totalBonusPaid);

    return { 
      totalReformed, 
      totalBonusEarned, 
      totalBonusPaid, 
      pendingBonuses 
    };
  }, [shipments]);

  useEffect(() => {
    if (stats.totalBonusEarned > lastBonusCount) {
      if (lastBonusCount > 0 || stats.totalBonusEarned === 1) { 
        setShowBonusAlert(true);
      }
      setLastBonusCount(stats.totalBonusEarned);
    }
  }, [stats.totalBonusEarned, lastBonusCount]);

  const handleLogin = (username: string) => {
    setCurrentUser(username);
    localStorage.setItem(AUTH_KEY, username);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_KEY);
    setView('dashboard');
  };

  const handleAddShipment = (data: { date: string, quantity: number }) => {
    const newShipment: Shipment = {
      id: crypto.randomUUID(),
      number: `REM-${String(shipments.length + 1).padStart(4, '0')}`,
      sendDate: data.date,
      quantitySent: data.quantity,
      status: ShipmentStatus.AWAITING,
      returns: []
    };
    setShipments([newShipment, ...shipments]);
    setView('dashboard');
  };

  const handleRegisterReturn = (id: string, event: ReturnEvent) => {
    setShipments(prev => prev.map(s => {
      if (s.id === id) {
        const updatedReturns = [...s.returns, event];
        const totalReturnedCount = updatedReturns.reduce((acc, r) => 
          acc + r.reformed + r.repaired + r.exchanged + r.failed, 0);

        let newStatus = ShipmentStatus.PARTIAL;
        if (totalReturnedCount >= s.quantitySent) {
          newStatus = ShipmentStatus.FINISHED;
        }

        return {
          ...s,
          status: newStatus,
          returns: updatedReturns
        };
      }
      return s;
    }));
    setView('dashboard');
  };

  const openReturnForm = (id: string) => {
    setActiveShipmentId(id);
    setView('return');
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-20 md:pb-0">
      <header className="bg-red-700 text-white p-4 shadow-lg sticky top-0 z-10">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Disc className="w-7 h-7 animate-spin-slow" />
            <h1 className="text-xl font-bold tracking-tight">Controle de Reformas</h1>
          </div>

          <div className="flex items-center gap-3">
            {isSyncing && (
              <div className="flex items-center gap-1 text-[10px] bg-red-800/50 px-2 py-1 rounded-full animate-pulse">
                <CloudUpload className="w-3 h-3" />
                <span>Sincronizando...</span>
              </div>
            )}
            <div className="hidden sm:flex items-center gap-2 text-xs font-medium bg-red-800/50 px-3 py-1.5 rounded-full border border-red-400/20">
              <UserIcon className="w-3 h-3" />
              {currentUser}
            </div>
            <div className="text-xs font-bold bg-yellow-500 text-red-900 px-3 py-1.5 rounded-full flex items-center gap-2 shadow-inner">
              <Gift className="w-3 h-3" />
              {stats.pendingBonuses} Pendentes
            </div>
            <button 
              onClick={handleLogout}
              className="p-2 hover:bg-red-600 rounded-full transition-colors text-red-100"
              title="Sair"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-4xl w-full mx-auto p-4 animate-in fade-in duration-500">
        {view === 'dashboard' && (
          <Dashboard 
            stats={stats} 
            onNewShipment={() => setView('new')} 
            onViewList={() => setView('list')}
            recentShipments={shipments.slice(0, 5)}
            onOpenReturn={openReturnForm}
          />
        )}

        {view === 'new' && (
          <ShipmentForm 
            onSave={handleAddShipment} 
            onCancel={() => setView('dashboard')} 
          />
        )}

        {view === 'list' && (
          <ShipmentList 
            shipments={shipments} 
            onOpenReturn={openReturnForm}
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={shipments.find(s => s.id === activeShipmentId)!}
            pendingBonuses={stats.pendingBonuses}
            onSave={(event) => handleRegisterReturn(activeShipmentId, event)}
            onCancel={() => setView('dashboard')}
          />
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-2 md:hidden flex justify-around items-center z-10">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-xs">Início</span>
        </button>
        <button 
          onClick={() => setView('new')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'new' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <div className="bg-red-600 text-white p-2 rounded-full -mt-8 shadow-lg ring-4 ring-slate-50">
            <Plus className="w-6 h-6" />
          </div>
          <span className="text-xs mt-1">Nova</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'list' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <History className="w-6 h-6" />
          <span className="text-xs">Histórico</span>
        </button>
      </nav>

      {showBonusAlert && (
        <BonusNotification 
          count={stats.totalBonusEarned} 
          onClose={() => setShowBonusAlert(false)} 
        />
      )}
    </div>
  );
};

export default App;

payload.text:
Entendo. O Google Apps Script **não cria a tabela automaticamente ao salvar o código**; ele só executa e cria as abas quando recebe o **primeiro sinal (dados)** vindo do seu aplicativo ou quando você executa uma função de teste.

Além disso, para que o Google Sheets aceite a conexão, a implantação deve estar configurada exatamente como "Qualquer pessoa" (Anyone), mesmo que seja anônima.

Aqui está o procedimento exato e o código atualizado para garantir que tudo funcione:

### 1. Novo Código para o Google Apps Script (Substitua tudo o que tem lá)

Este código agora inclui uma função `doGet` para você testar no navegador e uma lógica mais robusta para criar a aba "Remessas" caso ela não exista.

```javascript
function doGet(e) {
  return ContentService.createTextOutput("✅ O Script está ativo! Aguardando dados do app Controle de Reformas.")
    .setMimeType(ContentService.MimeType.TEXT);
}

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(10000); // Espera até 10 segundos para evitar conflitos de escrita simultânea

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    let sheet = ss.getSheetByName("Remessas");

    // Se a aba não existir, cria e configura o cabeçalho
    if (!sheet) {
      sheet = ss.insertSheet("Remessas");
      sheet.appendRow(["ID", "Número", "Data Envio", "Quantidade Enviada", "Status Atual", "Total Retornado", "Bônus Utilizados", "Dados Completos (JSON)", "Última Sincronização"]);
      sheet.getRange(1, 1, 1, 9).setFontWeight("bold").setBackground("#f8d7da");
      sheet.setFrozenRows(1);
    }

    const data = JSON.parse(e.postData.contents);
    const shipments = data.shipments;

    // Limpa apenas os dados (mantendo o cabeçalho) para atualizar com a lista mais recente
    if (sheet.getLastRow() > 1) {
      sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();
    }

    shipments.forEach(s => {
      const totalReturned = s.returns.reduce((sum, r) => sum + r.reformed + r.repaired + r.exchanged + r.failed, 0);
      const bonusCount = s.returns.filter(r => r.bonusUsed).length;

      sheet.appendRow([
        s.id,
        s.number,
        s.sendDate,
        s.quantitySent,
        s.status,
        totalReturned,
        bonusCount,
        JSON.stringify(s.returns),
        new Date()
      ]);
    });

    return ContentService.createTextOutput(JSON.stringify({ "status": "success" }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ "status": "error", "message": err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}
```

### 2. Passos para que a tabela apareça:

1.  No Apps Script, clique em **Implantar > Nova Implantação**.
2.  Tipo: **App da Web**.
3.  Executar como: **Eu** (seu e-mail).
4.  Quem pode acessar: **Qualquer pessoa** (Isso é crucial).
5.  Clique em **Implantar** e **Autorize o acesso** (o Google dirá que o app não é verificado, clique em "Avançado" e "Ir para...").
6.  **No Aplicativo:** Adicione uma nova remessa ou registre um retorno. O app enviará os dados e, nesse momento, a aba "Remessas" aparecerá magicamente na sua planilha.

---

### 3. Atualização no App (App.tsx)
Vou adicionar um pequeno indicador visual de "Sincronizado" para você ter certeza de que o envio foi feito.

