  PARTIAL = 'Retorno Parcial',
  FINISHED = 'Finalizada'
}

export interface ReturnEvent {
  id: string;
  date: string;
  invoiceNumber: string;
  reformed: number;
  repaired: number;
  exchanged: number;
  failed: number;
  bonusesRedeemed?: number;
}

export interface Shipment {
  id: string;
  number: string;
  sendDate: string;
  quantitySent: number;
  status: ShipmentStatus;
  returns: ReturnEvent[];
}

export interface BonusStats {
  totalReformed: number;
  totalBonusEarned: number;
  totalBonusPaid: number;
  pendingBonuses: number;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Disc, 
  RotateCcw, 
  Plus, 
  BarChart3, 
  CheckCircle2, 
  Clock, 
  ChevronRight, 
  AlertCircle,
  Trophy,
  History,
  LayoutDashboard,
  LogOut,
  User as UserIcon,
  PieChart,
  Gift,
  CloudUpload,
  Check
} from 'lucide-react';
import { Shipment, ShipmentStatus, ReturnEvent, BonusStats } from './types';
import Dashboard from './components/Dashboard';
import ShipmentList from './components/ShipmentList';
import ShipmentForm from './components/ShipmentForm';
import ReturnForm from './components/ReturnForm';
import BonusNotification from './components/BonusNotification';
import Login from './components/Login';

const STORAGE_KEY = 'pneucontrol_data_v3';
const AUTH_KEY = 'pneucontrol_user';
const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbwi-YwN4a8TuVIt3fV1Ujyk20JgwU6vn0zen2ojg4S4RimfW_5ep7nuX4a4kt8IRbo/exec';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<string | null>(null);
  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [view, setView] = useState<'dashboard' | 'new' | 'list' | 'return'>('dashboard');
  const [activeShipmentId, setActiveShipmentId] = useState<string | null>(null);
  const [showBonusAlert, setShowBonusAlert] = useState(false);
  const [lastBonusCount, setLastBonusCount] = useState(0);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');

  useEffect(() => {
    const savedUser = localStorage.getItem(AUTH_KEY);
    if (savedUser) setCurrentUser(savedUser);

    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        setShipments(parsed);
      } catch (e) {
        console.error("Failed to parse local storage", e);
      }
    }
  }, []);

  // Sincronização com LocalStorage e Google Sheets
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(shipments));

    const syncWithSheets = async () => {
      if (shipments.length === 0) return;
      setSyncStatus('syncing');
      try {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: 'POST',
          mode: 'no-cors',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ shipments }),
        });
        setSyncStatus('success');
        setTimeout(() => setSyncStatus('idle'), 3000);
      } catch (error) {
        console.error("Erro ao sincronizar com Google Sheets:", error);
        setSyncStatus('error');
        setTimeout(() => setSyncStatus('idle'), 5000);
      }
    };

    const timeoutId = setTimeout(syncWithSheets, 1500); 
    return () => clearTimeout(timeoutId);
  }, [shipments]);

  const stats: BonusStats = useMemo(() => {
    let totalReformed = 0;
    let totalBonusPaid = 0;

    shipments.forEach(s => {
      s.returns.forEach(r => {
        totalReformed += r.reformed;
        totalBonusPaid += r.bonusesRedeemed || 0;
      });
    });

    const totalBonusEarned = Math.floor(totalReformed / 15);
    const pendingBonuses = Math.max(0, totalBonusEarned - totalBonusPaid);

    return { 
      totalReformed, 
      totalBonusEarned, 
      totalBonusPaid, 
      pendingBonuses 
    };
  }, [shipments]);

  useEffect(() => {
    if (stats.totalBonusEarned > lastBonusCount) {
      if (lastBonusCount > 0 || stats.totalBonusEarned === 1) { 
        setShowBonusAlert(true);
      }
      setLastBonusCount(stats.totalBonusEarned);
    }
  }, [stats.totalBonusEarned, lastBonusCount]);

  const handleLogin = (username: string) => {
    setCurrentUser(username);
    localStorage.setItem(AUTH_KEY, username);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_KEY);
    setView('dashboard');
  };

  const handleAddShipment = (data: { date: string, quantity: number }) => {
    const newShipment: Shipment = {
      id: crypto.randomUUID(),
      number: `REM-${String(shipments.length + 1).padStart(4, '0')}`,
      sendDate: data.date,
      quantitySent: data.quantity,
      status: ShipmentStatus.AWAITING,
      returns: []
    };
    setShipments([newShipment, ...shipments]);
    setView('dashboard');
  };

  const handleRegisterReturn = (id: string, event: ReturnEvent) => {
    setShipments(prev => prev.map(s => {
      if (s.id === id) {
        const updatedReturns = [...s.returns, event];
        const totalReturnedCount = updatedReturns.reduce((acc, r) => 
          acc + r.reformed + r.repaired + r.exchanged + r.failed, 0);

        let newStatus = ShipmentStatus.PARTIAL;
        if (totalReturnedCount >= s.quantitySent) {
          newStatus = ShipmentStatus.FINISHED;
        }

        return {
          ...s,
          status: newStatus,
          returns: updatedReturns
        };
      }
      return s;
    }));
    setView('dashboard');
  };

  const openReturnForm = (id: string) => {
    setActiveShipmentId(id);
    setView('return');
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-20 md:pb-0">
      <header className="bg-red-700 text-white p-4 shadow-lg sticky top-0 z-10">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Disc className="w-7 h-7 animate-spin-slow" />
            <h1 className="text-xl font-bold tracking-tight">Controle de Reformas</h1>
          </div>

          <div className="flex items-center gap-3">
            {syncStatus !== 'idle' && (
              <div className={`flex items-center gap-1 text-[10px] px-2 py-1 rounded-full border ${
                syncStatus === 'syncing' ? 'bg-red-800/50 border-red-400/20 animate-pulse' :
                syncStatus === 'success' ? 'bg-green-500/20 border-green-400/40 text-green-100' :
                'bg-yellow-500/20 border-yellow-400/40 text-yellow-100'
              }`}>
                {syncStatus === 'syncing' && <CloudUpload className="w-3 h-3" />}
                {syncStatus === 'success' && <Check className="w-3 h-3" />}
                {syncStatus === 'error' && <AlertCircle className="w-3 h-3" />}
                <span className="hidden xs:inline">
                  {syncStatus === 'syncing' ? 'Sincronizando...' : 
                   syncStatus === 'success' ? 'Salvo no Google Sheets' : 'Erro na sincronização'}
                </span>
              </div>
            )}
            <div className="hidden sm:flex items-center gap-2 text-xs font-medium bg-red-800/50 px-3 py-1.5 rounded-full border border-red-400/20">
              <UserIcon className="w-3 h-3" />
              {currentUser}
            </div>
            <div className="text-xs font-bold bg-yellow-500 text-red-900 px-3 py-1.5 rounded-full flex items-center gap-2 shadow-inner">
              <Gift className="w-3 h-3" />
              {stats.pendingBonuses} Pendentes
            </div>
            <button 
              onClick={handleLogout}
              className="p-2 hover:bg-red-600 rounded-full transition-colors text-red-100"
              title="Sair"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-4xl w-full mx-auto p-4 animate-in fade-in duration-500">
        {view === 'dashboard' && (
          <Dashboard 
            stats={stats} 
            onNewShipment={() => setView('new')} 
            onViewList={() => setView('list')}
            recentShipments={shipments.slice(0, 5)}
            onOpenReturn={openReturnForm}
          />
        )}

        {view === 'new' && (
          <ShipmentForm 
            onSave={handleAddShipment} 
            onCancel={() => setView('dashboard')} 
          />
        )}

        {view === 'list' && (
          <ShipmentList 
            shipments={shipments} 
            onOpenReturn={openReturnForm}
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={shipments.find(s => s.id === activeShipmentId)!}
            pendingBonuses={stats.pendingBonuses}
            onSave={(event) => handleRegisterReturn(activeShipmentId, event)}
            onCancel={() => setView('dashboard')}
          />
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-2 md:hidden flex justify-around items-center z-10">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-xs">Início</span>
        </button>
        <button 
          onClick={() => setView('new')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'new' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <div className="bg-red-600 text-white p-2 rounded-full -mt-8 shadow-lg ring-4 ring-slate-50">
            <Plus className="w-6 h-6" />
          </div>
          <span className="text-xs mt-1">Nova</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'list' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <History className="w-6 h-6" />
          <span className="text-xs">Histórico</span>
        </button>
      </nav>

      {showBonusAlert && (
        <BonusNotification 
          count={stats.totalBonusEarned} 
          onClose={() => setShowBonusAlert(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { X, Save, AlertCircle, FileText, Calendar, Info, Gift, CheckCircle, Minus, Plus } from 'lucide-react';
import { Shipment, ReturnEvent } from '../types';

interface ReturnFormProps {
  shipment: Shipment;
  pendingBonuses: number;
  onSave: (event: ReturnEvent) => void;
  onCancel: () => void;
}

const ReturnForm: React.FC<ReturnFormProps> = ({ shipment, pendingBonuses, onSave, onCancel }) => {
  const [reformed, setReformed] = useState(0);
  const [repaired, setRepaired] = useState(0);
  const [exchanged, setExchanged] = useState(0);
  const [failed, setFailed] = useState(0);
  const [returnDate, setReturnDate] = useState(new Date().toISOString().split('T')[0]);
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [bonusesToRedeem, setBonusesToRedeem] = useState(0);

  const alreadyReturned = useMemo(() => {
    return shipment.returns.reduce((sum, r) => sum + r.reformed + r.repaired + r.exchanged + r.failed, 0);
  }, [shipment.returns]);

  const currentTotalInThisForm = reformed + repaired + exchanged + failed;
  const remainingTotal = shipment.quantitySent - alreadyReturned;
  const canSave = currentTotalInThisForm > 0 && currentTotalInThisForm <= remainingTotal && invoiceNumber.trim().length > 0;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!canSave) return;

    const newEvent: ReturnEvent = {
      id: crypto.randomUUID(),
      date: returnDate,
      invoiceNumber: invoiceNumber.trim(),
      reformed,
      repaired,
      exchanged,
      failed,
      bonusesRedeemed: bonusesToRedeem
    };

    onSave(newEvent);
  };

  const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
    e.target.select();
  };

  const incrementBonus = () => {
    if (bonusesToRedeem < pendingBonuses) {
      setBonusesToRedeem(prev => prev + 1);
    }
  };

  const decrementBonus = () => {
    if (bonusesToRedeem > 0) {
      setBonusesToRedeem(prev => prev - 1);
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden animate-in zoom-in-95 duration-200">
      <div className="bg-slate-800 text-white p-4 flex justify-between items-center">
        <div>
          <h2 className="text-lg font-bold">Registrar Retorno</h2>
          <p className="text-xs text-slate-400">Referente a {shipment.number}</p>
        </div>
        <button onClick={onCancel} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
          <X className="w-6 h-6" />
        </button>
      </div>

      <div className="grid grid-cols-2 bg-slate-50 p-4 border-b border-slate-200 divide-x divide-slate-200">
        <div className="text-center px-2">
          <p className="text-[10px] font-bold text-slate-400 uppercase">Total Enviado</p>
          <p className="text-xl font-black text-slate-700">{shipment.quantitySent}</p>
        </div>
        <div className="text-center px-2">
          <p className="text-[10px] font-bold text-slate-400 uppercase">Pendente</p>
          <p className="text-xl font-black text-red-600">{remainingTotal}</p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-5">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-bold text-slate-600 mb-1 flex items-center gap-1">
              <Calendar className="w-3 h-3 text-red-600" /> Data de Retorno
            </label>
            <input 
              type="date"
              value={returnDate}
              onChange={(e) => setReturnDate(e.target.value)}
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 focus:ring-2 focus:ring-red-500 outline-none transition-all"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-600 mb-1 flex items-center gap-1">
              <FileText className="w-3 h-3 text-red-600" /> Número da Nota
            </label>
            <input 
              type="text"
              value={invoiceNumber}
              onChange={(e) => setInvoiceNumber(e.target.value)}
              placeholder="Ex: NF-12345"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 focus:ring-2 focus:ring-red-500 outline-none transition-all"
              required
            />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="block text-xs font-bold text-green-700">REFORMADOS</label>
            <input 
              type="number"
              min="0"
              value={reformed}
              onFocus={handleFocus}
              onChange={(e) => setReformed(Math.max(0, parseInt(e.target.value) || 0))}
              className="w-full bg-green-50/30 border border-green-100 rounded-xl p-3 text-lg font-bold text-green-700 focus:ring-2 focus:ring-green-500 outline-none"
            />
          </div>
          <div className="space-y-1">
            <label className="block text-xs font-bold text-red-700">CONSERTADOS</label>
            <input 
              type="number"
              min="0"
              value={repaired}
              onFocus={handleFocus}
              onChange={(e) => setRepaired(Math.max(0, parseInt(e.target.value) || 0))}
              className="w-full bg-red-50/30 border border-red-100 rounded-xl p-3 text-lg font-bold text-red-700 focus:ring-2 focus:ring-red-500 outline-none"
            />
          </div>
          <div className="space-y-1">
            <label className="block text-xs font-bold text-purple-700">TROCADOS</label>
            <input 
              type="number"
              min="0"
              value={exchanged}
              onFocus={handleFocus}
              onChange={(e) => setExchanged(Math.max(0, parseInt(e.target.value) || 0))}
              className="w-full bg-purple-50/30 border border-purple-100 rounded-xl p-3 text-lg font-bold text-purple-700 focus:ring-2 focus:ring-purple-500 outline-none"
            />
          </div>
          <div className="space-y-1">
            <label className="block text-xs font-bold text-red-900">SEM REFORMA</label>
            <input 
              type="number"
              min="0"
              value={failed}
              onFocus={handleFocus}
              onChange={(e) => setFailed(Math.max(0, parseInt(e.target.value) || 0))}
              className="w-full bg-red-50/30 border border-red-200 rounded-xl p-3 text-lg font-bold text-red-900 focus:ring-2 focus:ring-red-500 outline-none"
            />
          </div>
        </div>

        {pendingBonuses > 0 && (
          <div className="p-4 rounded-2xl border-2 border-slate-100 bg-white shadow-sm transition-all">
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-full ${bonusesToRedeem > 0 ? 'bg-yellow-400 text-white' : 'bg-slate-100 text-slate-400'}`}>
                  <Gift className="w-5 h-5" />
                </div>
                <div>
                  <p className="font-bold text-sm">Resgatar bônus?</p>
                  <p className="text-[10px] font-medium opacity-70">Disponíveis: {pendingBonuses}</p>
                </div>
              </div>
              {bonusesToRedeem > 0 && <CheckCircle className="w-6 h-6 text-yellow-500" />}
            </div>

            <div className="flex items-center justify-center gap-6 bg-slate-50 p-3 rounded-xl border border-slate-200">
              <button 
                type="button" 
                onClick={decrementBonus}
                disabled={bonusesToRedeem === 0}
                className="p-2 bg-white rounded-full border border-slate-200 shadow-sm text-slate-500 disabled:opacity-30 active:scale-95 transition-all"
              >
                <Minus className="w-5 h-5" />
              </button>

              <div className="text-center min-w-[3rem]">
                <p className="text-2xl font-black text-slate-800">{bonusesToRedeem}</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Resgatando</p>
              </div>

              <button 
                type="button" 
                onClick={incrementBonus}
                disabled={bonusesToRedeem >= pendingBonuses}
                className="p-2 bg-white rounded-full border border-slate-200 shadow-sm text-yellow-600 disabled:opacity-30 active:scale-95 transition-all"
              >
                <Plus className="w-5 h-5" />
              </button>
            </div>
          </div>
        )}

        <div className={`p-4 rounded-xl flex items-center justify-between transition-colors ${currentTotalInThisForm > remainingTotal ? 'bg-red-100 text-red-800' : currentTotalInThisForm === remainingTotal ? 'bg-green-100 text-green-800' : 'bg-red-50 text-red-800'}`}>
          <div className="flex items-center gap-2">
            <Info className="w-5 h-5" />
            <span className="text-sm font-bold">Lançamento Atual: {currentTotalInThisForm} pneus</span>
          </div>
          {currentTotalInThisForm > remainingTotal ? (
            <span className="text-xs font-black uppercase">Excede o limite!</span>
          ) : (
            <span className="text-xs font-black uppercase">{currentTotalInThisForm === remainingTotal ? 'Fechamento Total' : 'Lançamento Parcial'}</span>
          )}
        </div>

        <button 
          type="submit"
          disabled={!canSave}
          className={`w-full font-bold py-4 rounded-xl shadow-lg flex items-center justify-center gap-2 transition-all active:scale-95 ${
            canSave 
              ? 'bg-red-600 hover:bg-red-700 text-white shadow-red-200' 
              : 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none'
          }`}
        >
          <Save className="w-5 h-5" />
          Registrar Retorno
        </button>
      </form>
    </div>
  );
};

export default ReturnForm;

import React, { useState } from 'react';
import { ChevronLeft, RotateCcw, Clock, CheckCircle2, History, ChevronDown, ChevronUp, FileText, Gift, AlertCircle } from 'lucide-react';
import { Shipment, ShipmentStatus } from '../types';

interface ShipmentListProps {
  shipments: Shipment[];
  onOpenReturn: (id: string) => void;
  onBack: () => void;
}

const ShipmentList: React.FC<ShipmentListProps> = ({ shipments, onOpenReturn, onBack }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4 mb-2">
        <button 
          onClick={onBack}
          className="p-2 hover:bg-slate-200 rounded-full transition-colors"
        >
          <ChevronLeft className="w-6 h-6 text-slate-600" />
        </button>
        <h2 className="text-xl font-bold text-slate-700">Histórico de Remessas</h2>
      </div>

      {shipments.length === 0 ? (
        <div className="bg-white rounded-2xl p-12 text-center text-slate-400 shadow-sm border border-slate-100">
          <History className="w-16 h-16 mx-auto mb-4 opacity-10" />
          <p className="text-lg">Nenhuma remessa registrada ainda.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {shipments.map((s) => {
            const totalReturned = s.returns.reduce((sum, r) => sum + r.reformed + r.repaired + r.exchanged + r.failed, 0);
            const isExpanded = expandedId === s.id;
            const progressPercent = (totalReturned / s.quantitySent) * 100;

            let dotColor = "bg-red-500";
            let statusTextColor = "text-red-500";

            if (s.status === ShipmentStatus.PARTIAL) {
              dotColor = "bg-yellow-400";
              statusTextColor = "text-yellow-600";
            } else if (s.status === ShipmentStatus.FINISHED) {
              dotColor = "bg-green-500";
              statusTextColor = "text-green-500";
            }

            return (
              <div key={s.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="p-4" onClick={() => toggleExpand(s.id)}>
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex items-center gap-2">
                      <div className={`w-3 h-3 rounded-full ${dotColor}`}></div>
                      <span className={`text-[10px] font-black uppercase ${statusTextColor}`}>{s.status}</span>
                    </div>
                    <span className="text-xs font-medium text-slate-400">{new Date(s.sendDate).toLocaleDateString()}</span>
                  </div>

                  <div className="flex justify-between items-center">
                    <div>
                      <h3 className="text-lg font-black text-slate-800 leading-tight">{s.number}</h3>
                      <p className="text-sm font-bold text-slate-500">{totalReturned} / {s.quantitySent} Pneus</p>
                    </div>

                    <div className="flex items-center gap-2">
                      {s.status !== ShipmentStatus.FINISHED && (
                        <button 
                          onClick={(e) => { e.stopPropagation(); onOpenReturn(s.id); }}
                          className="bg-red-600 hover:bg-red-700 text-white p-2 rounded-xl shadow-md active:scale-95 transition-all"
                        >
                          <RotateCcw className="w-5 h-5" />
                        </button>
                      )}
                      <div className="p-1 text-slate-400">
                        {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                      </div>
                    </div>
                  </div>

                  <div className="mt-3 w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                    <div 
                      className={`h-full rounded-full transition-all duration-500 ${
                        s.status === ShipmentStatus.FINISHED ? 'bg-green-500' : 
                        s.status === ShipmentStatus.PARTIAL ? 'bg-yellow-400' : 'bg-red-500'
                      }`}
                      style={{ width: `${progressPercent}%` }}
                    ></div>
