import React from 'react';
import { BarChart3, Trophy, Plus, ArrowRight, Clock, CheckCircle2, Disc, RotateCcw, Gift, AlertCircle } from 'lucide-react';
import { BonusStats, Shipment, ShipmentStatus } from '../types';

interface DashboardProps {
  stats: BonusStats;
  onNewShipment: () => void;
  onViewList: () => void;
  recentShipments: Shipment[];
  onOpenReturn: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, onNewShipment, onViewList, recentShipments, onOpenReturn }) => {
  // O progresso para o próximo bônus é baseado em pneus pagos (Reformados - Usados como bônus)
  const paidReforms = Math.max(0, stats.totalReformed - stats.totalBonusPaid);
  const nextBonusProgress = paidReforms % 15;
  const progressPercent = (nextBonusProgress / 15) * 100;

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="bg-red-100 p-3 rounded-xl text-red-600">
            <BarChart3 className="w-6 h-6" />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Total Reformas</p>
            <p className="text-2xl font-bold">{stats.totalReformed}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="bg-yellow-100 p-3 rounded-xl text-yellow-600">
            <Gift className="w-6 h-6" />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Bônus Disponíveis</p>
            <p className="text-2xl font-bold">{stats.pendingBonuses}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-center">
          <div className="flex justify-between items-end mb-2">
            <p className="text-sm text-slate-500 font-medium">Próximo Bônus</p>
            <p className="text-xs font-bold text-red-600">{nextBonusProgress}/15</p>
          </div>
          <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
            <div 
              className="bg-red-600 h-full rounded-full transition-all duration-1000 ease-out"
              style={{ width: `${progressPercent}%` }}
            ></div>
          </div>
        </div>
      </div>

      <div className="flex gap-4">
        <button 
          onClick={onNewShipment}
          className="flex-1 bg-red-600 hover:bg-red-700 text-white font-bold py-4 px-6 rounded-2xl shadow-md transition-all flex items-center justify-center gap-2 text-lg active:scale-95"
        >
          <Plus className="w-6 h-6" />
          Nova Remessa
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-50 flex justify-between items-center">
          <h2 className="font-bold text-slate-700">Últimas Remessas</h2>
          <button 
            onClick={onViewList}
            className="text-red-600 text-sm font-semibold flex items-center gap-1 hover:underline"
          >
            Ver todas <ArrowRight className="w-4 h-4" />
          </button>
        </div>

        {recentShipments.length === 0 ? (
          <div className="p-10 text-center text-slate-400">
            <Disc className="w-12 h-12 mx-auto mb-2 opacity-20" />
            <p>Nenhuma remessa encontrada.</p>
          </div>
        ) : (
          <div className="divide-y divide-slate-50">
            {recentShipments.map((shipment) => {
               const totalReturned = shipment.returns.reduce((sum, r) => sum + r.reformed + r.repaired + r.exchanged + r.failed, 0);

               let statusStyles = "bg-red-100 text-red-600";
               let StatusIcon = AlertCircle;

               if (shipment.status === ShipmentStatus.PARTIAL) {
                 statusStyles = "bg-yellow-100 text-yellow-600";
                 StatusIcon = Clock;
               } else if (shipment.status === ShipmentStatus.FINISHED) {
                 statusStyles = "bg-green-100 text-green-600";
                 StatusIcon = CheckCircle2;
               }

               return (
                <div key={shipment.id} className="p-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-full ${statusStyles}`}>
                      <StatusIcon className="w-5 h-5" />
                    </div>
                    <div>
                      <p className="font-bold text-slate-800">{shipment.number}</p>
                      <p className="text-xs text-slate-500">{new Date(shipment.sendDate).toLocaleDateString()}</p>
                    </div>
                  </div>

                  <div className="flex items-center gap-4">
                    <div className="text-right hidden sm:block">
                      <p className="text-sm font-semibold text-slate-700">{totalReturned} / {shipment.quantitySent} pneus</p>
                      <p className={`text-xs font-bold ${
                        shipment.status === ShipmentStatus.AWAITING ? 'text-red-500' : 
