Para permitir que os logins sejam gerenciados diretamente pelo banco de dados (Google Sheets), precisamos de duas partes: uma atualização no código do **Apps Script** (para ler os usuários da planilha) e uma atualização no **React** (para buscar esses dados ao carregar o app).

### 1. Atualização do Google Apps Script (Copie e cole no seu script)

Este código cria automaticamente a aba "Usuarios" se ela não existir e permite que o App busque os nomes e senhas.

```javascript
// Adicione esta função doGet ao seu script existente
function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let userSheet = ss.getSheetByName("Usuarios");

  // Cria a planilha de usuários se não existir
  if (!userSheet) {
    userSheet = ss.insertSheet("Usuarios");
    userSheet.appendRow(["username", "password"]);
    userSheet.appendRow(["Éder", "123456"]);
    userSheet.appendRow(["Wender", "123456"]);
    userSheet.appendRow(["Kesley", "123456"]);
    userSheet.appendRow(["Roberto", "123456"]);
  }

  const data = userSheet.getDataRange().getValues();
  const users = [];
  // Pula o cabeçalho
  for (let i = 1; i < data.length; i++) {
    if (data[i][0]) {
      users.push({ 
        username: String(data[i][0]), 
        password: String(data[i][1]) 
      });
    }
  }

  return ContentService.createTextOutput(JSON.stringify(users))
    .setMimeType(ContentService.MimeType.JSON);
}

