        {view === 'list' && (
          <ShipmentList 
            shipments={shipments} 
            onOpenReturn={openReturnForm}
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={shipments.find(s => s.id === activeShipmentId)!}
