      }
    } catch (error) {
      console.warn("Usando lista de usuários padrão devido a erro de conexão:", error);
      setValidUsers([
        { username: "Éder", password: "1" },
        { username: "Wender", password: "1" },
        { username: "Kesley", password: "1" },
        { username: "Roberto", password: "1" }
      ]);
    } finally {
      setLoadingUsers(false);
    }
  }, []);

  useEffect(() => {
    const savedUser = localStorage.getItem(AUTH_KEY);
    if (savedUser) setCurrentUser(savedUser);

    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        setShipments(parsed);
      } catch (e) {
        console.error("Failed to parse local storage", e);
      }
    }

    fetchUsers();
  }, [fetchUsers]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(shipments));

    const syncWithSheets = async () => {
      if (shipments.length === 0) return;
      setSyncStatus('syncing');
      try {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: 'POST',
          mode: 'no-cors',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ shipments }),
        });
        setSyncStatus('success');
        setTimeout(() => setSyncStatus('idle'), 3000);
      } catch (error) {
        console.error("Erro ao sincronizar com Google Sheets:", error);
        setSyncStatus('error');
        setTimeout(() => setSyncStatus('idle'), 5000);
      }
    };

    const timeoutId = setTimeout(syncWithSheets, 1500); 
    return () => clearTimeout(timeoutId);
  }, [shipments]);

  const stats: BonusStats = useMemo(() => {
    let totalReformed = 0;
    let totalBonusPaid = 0;

    shipments.forEach(s => {
      s.returns.forEach(r => {
        totalReformed += r.reformed;
        totalBonusPaid += r.bonusesRedeemed || 0;
      });
    });

    const paidReforms = Math.max(0, totalReformed - totalBonusPaid);
    const totalEarned = Math.floor(paidReforms / 15);
    const pendingBonuses = Math.max(0, totalEarned - totalBonusPaid);

    return { 
      totalReformed, 
      totalBonusEarned: totalEarned, 
      totalBonusPaid, 
      pendingBonuses 
    };
  }, [shipments]);

  const allInvoiceNumbers = useMemo(() => {
    const numbers: string[] = [];
    shipments.forEach(s => {
      s.returns.forEach(r => {
        numbers.push(r.invoiceNumber.toLowerCase());
      });
    });
    return numbers;
  }, [shipments]);

  useEffect(() => {
    if (stats.pendingBonuses > lastBonusCount) {
      setShowBonusAlert(true);
      setLastBonusCount(stats.pendingBonuses);
    } else if (stats.pendingBonuses < lastBonusCount) {
      setLastBonusCount(stats.pendingBonuses);
    }
  }, [stats.pendingBonuses, lastBonusCount]);

  const handleLogin = (username: string) => {
    setCurrentUser(username);
    localStorage.setItem(AUTH_KEY, username);
  };

  const handleRegister = async (username: string, password: string): Promise<boolean> => {
    try {
      setSyncStatus('syncing');
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
          action: 'register', 
          user: { username, password } 
        }),
      });
      setSyncStatus('success');
      // Recarrega a lista de usuários para incluir o novo
      await fetchUsers();
      return true;
    } catch (error) {
      console.error("Erro ao cadastrar usuário:", error);
      setSyncStatus('error');
      return false;
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_KEY);
    setView('dashboard');
  };

  const handleAddShipment = (data: { date: string, quantity: number }) => {
    const newShipment: Shipment = {
      id: crypto.randomUUID(),
      number: `REM-${String(shipments.length + 1).padStart(4, '0')}`,
      sendDate: data.date,
      quantitySent: data.quantity,
      status: ShipmentStatus.AWAITING,
      returns: []
    };
    setShipments([newShipment, ...shipments]);
    setView('dashboard');
  };

  const handleRegisterReturn = (id: string, event: ReturnEvent) => {
    setShipments(prev => prev.map(s => {
      if (s.id === id) {
        const updatedReturns = [...s.returns, event];
        const totalReturnedCount = updatedReturns.reduce((acc, r) => 
          acc + r.reformed + r.repaired + r.exchanged + r.failed, 0);

        let newStatus = ShipmentStatus.PARTIAL;
        if (totalReturnedCount >= s.quantitySent) {
          newStatus = ShipmentStatus.FINISHED;
        }

        return {
          ...s,
          status: newStatus,
          returns: updatedReturns
        };
      }
      return s;
    }));
    setView('dashboard');
  };

  const openReturnForm = (id: string) => {
    setActiveShipmentId(id);
    setView('return');
  };

  if (!currentUser) {
    return (
      <Login 
        onLogin={handleLogin} 
        onRegister={handleRegister}
        validUsers={validUsers} 
        isLoading={loadingUsers} 
      />
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-20 md:pb-0">
      <header className="bg-red-700 text-white p-4 shadow-lg sticky top-0 z-10">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Disc className="w-7 h-7 animate-spin-slow" />
            <h1 className="text-xl font-bold tracking-tight">Controle de Reformas</h1>
          </div>

          <div className="flex items-center gap-3">
            {syncStatus !== 'idle' && (
              <div className={`flex items-center gap-1 text-[10px] px-2 py-1 rounded-full border ${
                syncStatus === 'syncing' ? 'bg-red-800/50 border-red-400/20 animate-pulse' :
                syncStatus === 'success' ? 'bg-green-500/20 border-green-400/40 text-green-100' :
                'bg-yellow-500/20 border-yellow-400/40 text-yellow-100'
              }`}>
                {syncStatus === 'syncing' && <CloudUpload className="w-3 h-3" />}
                {syncStatus === 'success' && <Check className="w-3 h-3" />}
                {syncStatus === 'error' && <AlertCircle className="w-3 h-3" />}
                <span className="hidden xs:inline">
                  {syncStatus === 'syncing' ? 'Sincronizando...' : 
                   syncStatus === 'success' ? 'Salvo no Google Sheets' : 'Erro na sincronização'}
                </span>
              </div>
            )}
            <div className="hidden sm:flex items-center gap-2 text-xs font-medium bg-red-800/50 px-3 py-1.5 rounded-full border border-red-400/20">
              <UserIcon className="w-3 h-3" />
              {currentUser}
            </div>
            <div className="text-xs font-bold bg-yellow-500 text-red-900 px-3 py-1.5 rounded-full flex items-center gap-2 shadow-inner">
              <Gift className="w-3 h-3" />
              {stats.pendingBonuses} Pendentes
            </div>
            <button 
              onClick={handleLogout}
              className="p-2 hover:bg-red-600 rounded-full transition-colors text-red-100"
              title="Sair"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-4xl w-full mx-auto p-4 animate-in fade-in duration-500">
        {view === 'dashboard' && (
          <Dashboard 
            stats={stats} 
            onNewShipment={() => setView('new')} 
            onViewList={() => setView('list')}
            recentShipments={shipments.slice(0, 5)}
            onOpenReturn={openReturnForm}
          />
        )}

        {view === 'new' && (
          <ShipmentForm 
            onSave={handleAddShipment} 
            onCancel={() => setView('dashboard')} 
          />
        )}

        {view === 'list' && (
          <ShipmentList 
            shipments={shipments} 
            onOpenReturn={openReturnForm}
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={shipments.find(s => s.id === activeShipmentId)!}
            pendingBonuses={stats.pendingBonuses}
            existingInvoiceNumbers={allInvoiceNumbers}
            onSave={(event) => handleRegisterReturn(activeShipmentId, event)}
            onCancel={() => setView('dashboard')}
          />
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-2 md:hidden flex justify-around items-center z-10">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-xs">Início</span>
        </button>
        <button 
          onClick={() => setView('new')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'new' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <div className="bg-red-600 text-white p-2 rounded-full -mt-8 shadow-lg ring-4 ring-slate-50">
            <Plus className="w-6 h-6" />
          </div>
          <span className="text-xs mt-1">Nova</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'list' ? 'text-red-600' : 'text-slate-500'}`}
        >
          <History className="w-6 h-6" />
          <span className="text-xs">Histórico</span>
        </button>
      </nav>

      {showBonusAlert && (
        <BonusNotification 
          availableCount={stats.pendingBonuses} 
          onClose={() => setShowBonusAlert(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Disc, Lock, User, AlertCircle, Loader2, UserPlus, LogIn } from 'lucide-react';

interface LoginProps {
  onLogin: (username: string) => void;
  onRegister: (username: string, password: string) => Promise<boolean>;
  validUsers: { username: string, password: string }[];
  isLoading: boolean;
}

const Login: React.FC<LoginProps> = ({ onLogin, onRegister, validUsers, isLoading }) => {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (mode === 'register') {
      if (password !== confirmPassword) {
        setError('As senhas não coincidem.');
        return;
      }
      if (password.length < 4) {
        setError('A senha deve ter pelo menos 4 caracteres.');
        return;
      }

      const userExists = validUsers.some(u => u.username.toLowerCase() === username.trim().toLowerCase());
      if (userExists) {
        setError('Este nome de usuário já está em uso.');
        return;
      }

      setIsProcessing(true);
      const success = await onRegister(username.trim(), password);
      setIsProcessing(false);

      if (success) {
        setMode('login');
        setError(null);
        alert('Cadastro realizado com sucesso! Agora você pode entrar.');
      } else {
        setError('Ocorreu um erro ao tentar cadastrar. Tente novamente.');
      }
    } else {
      const user = validUsers.find(
        (u) => u.username.toLowerCase() === username.trim().toLowerCase() && u.password === password
      );

      if (user) {
        onLogin(user.username);
      } else {
        setError('Usuário ou senha inválidos.');
      }
    }
  };

  const toggleMode = () => {
    setMode(mode === 'login' ? 'register' : 'login');
    setError(null);
    setPassword('');
    setConfirmPassword('');
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-20 h-20 bg-red-600 text-white rounded-3xl shadow-xl shadow-red-200 mb-4 animate-in fade-in slide-in-from-top-4 duration-700">
            <Disc className="w-10 h-10 animate-spin-slow" />
          </div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Controle de Reformas</h1>
          <p className="text-slate-500 font-medium mt-2">Gestão de Manutenção e Bônus</p>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-xl shadow-slate-200/60 border border-slate-100 animate-in zoom-in-95 duration-500">
          <h2 className="text-xl font-bold text-slate-800 mb-6">
            {mode === 'login' ? 'Acesse sua conta' : 'Criar nova conta'}
          </h2>

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <label className="block text-sm font-bold text-slate-600 mb-2">Usuário</label>
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input 
                  type="text"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="Seu nome de usuário"
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 pl-12 text-slate-800 focus:ring-2 focus:ring-red-500 focus:border-red-500 transition-all outline-none"
                  required
                  disabled={isLoading || isProcessing}
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-600 mb-2">Senha</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input 
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 pl-12 text-slate-800 focus:ring-2 focus:ring-red-500 focus:border-red-500 transition-all outline-none"
                  required
                  disabled={isLoading || isProcessing}
                />
              </div>
            </div>

            {mode === 'register' && (
              <div className="animate-in slide-in-from-top-2 duration-300">
                <label className="block text-sm font-bold text-slate-600 mb-2">Confirmar Senha</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                  <input 
                    type="password"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    placeholder="••••••••"
                    className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 pl-12 text-slate-800 focus:ring-2 focus:ring-red-500 focus:border-red-500 transition-all outline-none"
                    required
                    disabled={isLoading || isProcessing}
                  />
                </div>
              </div>
            )}

            {error && (
              <div className="flex items-center gap-2 text-red-600 bg-red-50 p-3 rounded-xl animate-in shake duration-300">
                <AlertCircle className="w-5 h-5 shrink-0" />
                <p className="text-sm font-bold">{error}</p>
              </div>
            )}

            <button 
              type="submit"
              disabled={isLoading || isProcessing}
              className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-2xl shadow-lg shadow-red-200 transition-all active:scale-95 disabled:bg-slate-300 disabled:shadow-none flex items-center justify-center gap-2"
            >
              {(isLoading || isProcessing) ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" />
                  {isProcessing ? 'Cadastrando...' : 'Carregando...'}
                </>
              ) : (
                mode === 'login' ? (
                  <><LogIn className="w-5 h-5" /> Entrar no Sistema</>
                ) : (
                  <><UserPlus className="w-5 h-5" /> Criar Conta</>
                )
              )}
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-50 text-center">
            <button 
              onClick={toggleMode}
              className="text-red-600 text-sm font-bold hover:underline transition-all"
            >
              {mode === 'login' ? 'Não tem conta? Cadastre-se' : 'Já possui conta? Faça login'}
            </button>
            <p className="text-[10px] text-slate-400 font-medium mt-6 uppercase tracking-widest">
              &copy; {new Date().getFullYear()} Controle de Reformas
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

export enum ShipmentStatus {
  AWAITING = 'Aguardando Retorno',
  PARTIAL = 'Retorno Parcial',
  FINISHED = 'Finalizada'
}

export interface ReturnEvent {
  id: string;
  date: string;
  invoiceNumber: string;
  reformed: number;
  repaired: number;
  exchanged: number;
  failed: number;
  bonusesRedeemed?: number;
}

export interface Shipment {
  id: string;
  number: string;
  sendDate: string;
  quantitySent: number;
  status: ShipmentStatus;
  returns: ReturnEvent[];
}

export interface BonusStats {
  totalSent: number;
  totalReformed: number;
  totalRepaired: number;
  totalExchanged: number;
  totalFailed: number;
  totalBonusEarned: number;
  totalBonusPaid: number;
  pendingBonuses: number;
}

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { 
  Disc, 
  RotateCcw, 
  Plus, 
  BarChart3, 
  CheckCircle2, 
  Clock, 
  ChevronRight, 
  AlertCircle,
  Trophy,
  History,
  LayoutDashboard,
  LogOut,
  User as UserIcon,
  PieChart,
  Gift,
  CloudUpload,
  Check,
  Moon,
  Sun,
  Settings
} from 'lucide-react';
import { Shipment, ShipmentStatus, ReturnEvent, BonusStats } from './types';
import Dashboard from './components/Dashboard';
import ShipmentList from './components/ShipmentList';
import ShipmentForm from './components/ShipmentForm';
import ReturnForm from './components/ReturnForm';
import BonusNotification from './components/BonusNotification';
import Login from './components/Login';
import PasswordChange from './components/PasswordChange';

const STORAGE_KEY = 'pneucontrol_data_v3';
const AUTH_KEY = 'pneucontrol_user';
const THEME_KEY = 'pneucontrol_theme';
const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbzpXLsLVFn0ULlwo-fU49lJRm3KW7EQHqxxH1BSQ7tXGh8K8dRIMm1stJ2MBTqt5B8/exec';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<string | null>(null);
  const [validUsers, setValidUsers] = useState<{username: string, password: string}[]>([]);
  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [view, setView] = useState<'dashboard' | 'new' | 'list' | 'return' | 'settings'>('dashboard');
  const [activeShipmentId, setActiveShipmentId] = useState<string | null>(null);
  const [showBonusAlert, setShowBonusAlert] = useState(false);
  const [lastBonusCount, setLastBonusCount] = useState(0);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [loadingUsers, setLoadingUsers] = useState(true);
  const [darkMode, setDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved === 'dark';
  });

  const fetchUsers = useCallback(async () => {
    setLoadingUsers(true);
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?t=${Date.now()}`);
      if (!response.ok) throw new Error("Erro na resposta do servidor");

      const data = await response.json();
      if (Array.isArray(data)) {
        setValidUsers(data);
      } else {
        throw new Error("Formato de dados inválido");
      }
    } catch (error) {
      console.warn("Usando lista de usuários padrão devido a erro de conexão:", error);
      setValidUsers([
        { username: "Éder", password: "1" },
        { username: "Wender", password: "1" },
        { username: "Kesley", password: "1" },
        { username: "Roberto", password: "1" }
      ]);
    } finally {
      setLoadingUsers(false);
    }
  }, []);

  useEffect(() => {
    const savedUser = localStorage.getItem(AUTH_KEY);
    if (savedUser) setCurrentUser(savedUser);

    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        setShipments(parsed);
      } catch (e) {
        console.error("Failed to parse local storage", e);
      }
    }

    fetchUsers();
  }, [fetchUsers]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, darkMode ? 'dark' : 'light');
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(shipments));

    const syncWithSheets = async () => {
      if (shipments.length === 0) return;
      setSyncStatus('syncing');
      try {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: 'POST',
          mode: 'no-cors',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ shipments }),
        });
        setSyncStatus('success');
        setTimeout(() => setSyncStatus('idle'), 3000);
      } catch (error) {
        console.error("Erro ao sincronizar com Google Sheets:", error);
        setSyncStatus('error');
        setTimeout(() => setSyncStatus('idle'), 5000);
      }
    };

    const timeoutId = setTimeout(syncWithSheets, 1500); 
    return () => clearTimeout(timeoutId);
  }, [shipments]);

  const stats: BonusStats = useMemo(() => {
    let totalSent = 0;
    let totalReformed = 0;
    let totalRepaired = 0;
    let totalExchanged = 0;
    let totalFailed = 0;
    let totalBonusPaid = 0;

    shipments.forEach(s => {
      totalSent += s.quantitySent;
      s.returns.forEach(r => {
        totalReformed += r.reformed;
        totalRepaired += r.repaired;
        totalExchanged += r.exchanged;
        totalFailed += r.failed;
        totalBonusPaid += r.bonusesRedeemed || 0;
      });
    });

    const paidReforms = Math.max(0, totalReformed - totalBonusPaid);
    const totalEarned = Math.floor(paidReforms / 15);
    const pendingBonuses = Math.max(0, totalEarned - totalBonusPaid);

    return { 
      totalSent,
      totalReformed,
      totalRepaired,
      totalExchanged,
      totalFailed,
      totalBonusEarned: totalEarned, 
      totalBonusPaid, 
      pendingBonuses 
    };
  }, [shipments]);

  const allInvoiceNumbers = useMemo(() => {
    const numbers: string[] = [];
    shipments.forEach(s => {
      s.returns.forEach(r => {
        numbers.push(r.invoiceNumber.toLowerCase());
      });
    });
    return numbers;
  }, [shipments]);

  useEffect(() => {
    if (stats.pendingBonuses > lastBonusCount) {
      setShowBonusAlert(true);
      setLastBonusCount(stats.pendingBonuses);
    } else if (stats.pendingBonuses < lastBonusCount) {
      setLastBonusCount(stats.pendingBonuses);
    }
  }, [stats.pendingBonuses, lastBonusCount]);

  const handleLogin = (username: string) => {
    setCurrentUser(username);
    localStorage.setItem(AUTH_KEY, username);
  };

  const handleRegister = async (username: string, password: string): Promise<boolean> => {
    try {
      setSyncStatus('syncing');
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
          action: 'register', 
          user: { username, password } 
        }),
      });
      setSyncStatus('success');
      await fetchUsers();
      return true;
    } catch (error) {
      console.error("Erro ao cadastrar usuário:", error);
      setSyncStatus('error');
      return false;
    }
  };

  const handleChangePassword = async (newPassword: string): Promise<boolean> => {
    if (!currentUser) return false;
    try {
      setSyncStatus('syncing');
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
          action: 'changePassword', 
          user: { username: currentUser, password: newPassword } 
        }),
      });
      setSyncStatus('success');
      await fetchUsers();
      return true;
    } catch (error) {
      console.error("Erro ao alterar senha:", error);
      setSyncStatus('error');
      return false;
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_KEY);
    setView('dashboard');
  };

  const handleAddShipment = (data: { date: string, quantity: number }) => {
    const newShipment: Shipment = {
      id: crypto.randomUUID(),
      number: `REM-${String(shipments.length + 1).padStart(4, '0')}`,
      sendDate: data.date,
      quantitySent: data.quantity,
      status: ShipmentStatus.AWAITING,
      returns: []
    };
    setShipments([newShipment, ...shipments]);
    setView('dashboard');
  };

  const handleRegisterReturn = (id: string, event: ReturnEvent) => {
    setShipments(prev => prev.map(s => {
      if (s.id === id) {
        const updatedReturns = [...s.returns, event];
        const totalReturnedCount = updatedReturns.reduce((acc, r) => 
          acc + r.reformed + r.repaired + r.exchanged + r.failed, 0);

        let newStatus = ShipmentStatus.PARTIAL;
        if (totalReturnedCount >= s.quantitySent) {
          newStatus = ShipmentStatus.FINISHED;
        }

        return {
          ...s,
          status: newStatus,
          returns: updatedReturns
        };
      }
      return s;
    }));
    setView('dashboard');
  };

  const openReturnForm = (id: string) => {
    setActiveShipmentId(id);
    setView('return');
  };

  if (!currentUser) {
    return (
      <Login 
        onLogin={handleLogin} 
        onRegister={handleRegister}
        validUsers={validUsers} 
        isLoading={loadingUsers} 
      />
    );
  }

  return (
    <div className={`min-h-screen ${darkMode ? 'dark bg-slate-900' : 'bg-slate-50'} flex flex-col pb-20 md:pb-0 transition-colors duration-300`}>
      <header className="bg-red-700 dark:bg-red-900 text-white p-4 shadow-lg sticky top-0 z-10">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Disc className="w-7 h-7 animate-spin-slow" />
            <h1 className="text-xl font-bold tracking-tight">Controle de Reformas</h1>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 hover:bg-red-600 dark:hover:bg-red-800 rounded-full transition-colors"
              title={darkMode ? "Modo Claro" : "Modo Escuro"}
            >
              {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            {syncStatus !== 'idle' && (
              <div className={`flex items-center gap-1 text-[10px] px-2 py-1 rounded-full border ${
                syncStatus === 'syncing' ? 'bg-red-800/50 border-red-400/20 animate-pulse' :
                syncStatus === 'success' ? 'bg-green-500/20 border-green-400/40 text-green-100' :
                'bg-yellow-500/20 border-yellow-400/40 text-yellow-100'
              }`}>
                {syncStatus === 'syncing' && <CloudUpload className="w-3 h-3" />}
                {syncStatus === 'success' && <Check className="w-3 h-3" />}
                {syncStatus === 'error' && <AlertCircle className="w-3 h-3" />}
                <span className="hidden xs:inline">
                  {syncStatus === 'syncing' ? 'Sincronizando...' : 
                   syncStatus === 'success' ? 'Salvo' : 'Erro'}
                </span>
              </div>
            )}

            <div className="flex items-center gap-1">
               <button 
                 onClick={() => setView('settings')}
                 className={`flex items-center gap-2 text-xs font-medium px-3 py-1.5 rounded-full border border-red-400/20 transition-colors ${view === 'settings' ? 'bg-white text-red-700' : 'bg-red-800/50 text-white'}`}
               >
                 <UserIcon className="w-3 h-3" />
                 <span className="hidden xs:inline">{currentUser}</span>
               </button>
            </div>

            <button 
              onClick={handleLogout}
              className="p-2 hover:bg-red-600 dark:hover:bg-red-800 rounded-full transition-colors text-red-100"
              title="Sair"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-4xl w-full mx-auto p-4 animate-in fade-in duration-500">
        {view === 'dashboard' && (
          <Dashboard 
            stats={stats} 
            onNewShipment={() => setView('new')} 
            onViewList={() => setView('list')}
            recentShipments={shipments.slice(0, 5)}
            onOpenReturn={openReturnForm}
          />
        )}

        {view === 'new' && (
          <ShipmentForm 
            onSave={handleAddShipment} 
            onCancel={() => setView('dashboard')} 
          />
        )}

        {view === 'list' && (
          <ShipmentList 
            shipments={shipments} 
            onOpenReturn={openReturnForm}
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={shipments.find(s => s.id === activeShipmentId)!}
            pendingBonuses={stats.pendingBonuses}
            existingInvoiceNumbers={allInvoiceNumbers}
            onSave={(event) => handleRegisterReturn(activeShipmentId, event)}
            onCancel={() => setView('dashboard')}
          />
        )}

        {view === 'settings' && (
          <PasswordChange 
            username={currentUser}
            validUsers={validUsers}
            onSave={handleChangePassword}
            onCancel={() => setView('dashboard')}
          />
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700 p-2 md:hidden flex justify-around items-center z-10 transition-colors">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-xs">Início</span>
        </button>
        <button 
          onClick={() => setView('new')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'new' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}
        >
          <div className="bg-red-600 dark:bg-red-700 text-white p-2 rounded-full -mt-8 shadow-lg ring-4 ring-slate-50 dark:ring-slate-900 transition-all">
            <Plus className="w-6 h-6" />
          </div>
          <span className="text-xs mt-1">Nova</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex flex-col items-center p-2 rounded-lg ${view === 'list' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}
        >
          <History className="w-6 h-6" />
          <span className="text-xs">Histórico</span>
        </button>
      </nav>

      {showBonusAlert && (
        <BonusNotification 
          availableCount={stats.pendingBonuses} 
          onClose={() => setShowBonusAlert(false)} 
        />
      )}
    </div>
  );
};

export default App;

