import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { 
  Disc, 
  RotateCcw, 
  Plus, 
  BarChart3, 
  CheckCircle2, 
  Clock, 
  ChevronRight, 
  AlertCircle,
  Trophy,
  History,
  LayoutDashboard,
  LogOut,
  User as UserIcon,
  PieChart,
  Gift,
  CloudUpload,
  Check,
  Moon,
  Sun,
  Settings
} from 'lucide-react';
import { Shipment, ShipmentStatus, ReturnEvent, BonusStats } from './types';
import Dashboard from './components/Dashboard';
import ShipmentList from './components/ShipmentList';
import ShipmentForm from './components/ShipmentForm';
import ReturnForm from './components/ReturnForm';
import BonusNotification from './components/BonusNotification';
import Login from './components/Login';
import PasswordChange from './components/PasswordChange';

const STORAGE_KEY = 'pneucontrol_data_v3';
const AUTH_KEY = 'pneucontrol_user';
const THEME_KEY = 'pneucontrol_theme';
const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbzpXLsLVFn0ULlwo-fU49lJRm3KW7EQHqxxH1BSQ7tXGh8K8dRIMm1stJ2MBTqt5B8/exec';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<string | null>(null);
  const [validUsers, setValidUsers] = useState<{username: string, password: string}[]>([]);
  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [view, setView] = useState<'dashboard' | 'new' | 'list' | 'return' | 'settings'>('dashboard');
  const [activeShipmentId, setActiveShipmentId] = useState<string | null>(null);
  const [showBonusAlert, setShowBonusAlert] = useState(false);
  const [lastBonusCount, setLastBonusCount] = useState(0);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [loadingInitial, setLoadingInitial] = useState(true);
  const [darkMode, setDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved === 'dark';
  });

  const fetchUsers = useCallback(async () => {
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getUsers&t=${Date.now()}`);
      if (!response.ok) throw new Error("Erro na resposta do servidor");
      const data = await response.json();
      if (Array.isArray(data)) setValidUsers(data);
    } catch (error) {
      console.warn("Usando lista de usuários padrão:", error);
      setValidUsers([
        { username: "Éder", password: "1" },
        { username: "Wender", password: "1" },
        { username: "Kesley", password: "1" },
        { username: "Roberto", password: "1" }
      ]);
    }
  }, []);

  const fetchShipments = useCallback(async () => {
    try {
      setSyncStatus('syncing');
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getShipments&t=${Date.now()}`);
      if (!response.ok) throw new Error("Erro na busca de dados");
      const data = await response.json();

      let incomingShipments: Shipment[] = [];
      if (data && Array.isArray(data.shipments)) {
        incomingShipments = data.shipments;
      } else if (data && Array.isArray(data)) {
        incomingShipments = data;
      }

      if (incomingShipments.length > 0) {
        setShipments(incomingShipments);
        setSyncStatus('success');
      } else {
        // Se o servidor retornar vazio mas temos dados locais, mantemos os locais
        const savedData = localStorage.getItem(STORAGE_KEY);
        if (savedData) {
          const parsed = JSON.parse(savedData);
          if (Array.isArray(parsed) && parsed.length > 0) {
            setShipments(parsed);
          }
        }
        setSyncStatus('idle');
      }
    } catch (error) {
      console.error("Erro ao buscar histórico do servidor:", error);
      setSyncStatus('error');
      const savedData = localStorage.getItem(STORAGE_KEY);
      if (savedData) {
        try {
          setShipments(JSON.parse(savedData));
        } catch (e) { console.error(e); }
      }
    } finally {
      setLoadingInitial(false);
      setTimeout(() => setSyncStatus('idle'), 2000);
    }
  }, []);

  useEffect(() => {
    const init = async () => {
      const savedUser = localStorage.getItem(AUTH_KEY);
      if (savedUser) setCurrentUser(savedUser);

      await fetchUsers();
      await fetchShipments();
    };
    init();
  }, [fetchUsers, fetchShipments]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, darkMode ? 'dark' : 'light');
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  useEffect(() => {
    if (loadingInitial) return;

    localStorage.setItem(STORAGE_KEY, JSON.stringify(shipments));

    const syncWithSheets = async () => {
      if (shipments.length === 0 && !loadingInitial) return;

      setSyncStatus('syncing');
      try {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: 'POST',
          mode: 'no-cors',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'syncShipments', shipments }),
        });
        setSyncStatus('success');
        setTimeout(() => setSyncStatus('idle'), 3000);
      } catch (error) {
        console.error("Erro ao sincronizar:", error);
        setSyncStatus('error');
      }
    };

    const timeoutId = setTimeout(syncWithSheets, 2000); 
    return () => clearTimeout(timeoutId);
  }, [shipments, loadingInitial]);

  const stats: BonusStats = useMemo(() => {
    let totalSent = 0;
    let totalReformed = 0;
    let totalRepaired = 0;
    let totalExchanged = 0;
    let totalFailed = 0;
    let totalBonusPaid = 0;

    (shipments || []).forEach(s => {
      totalSent += (s.quantitySent || 0);
      (s.returns || []).forEach(r => {
        totalReformed += (r.reformed || 0);
        totalRepaired += (r.repaired || 0);
        totalExchanged += (r.exchanged || 0);
        totalFailed += (r.failed || 0);
        totalBonusPaid += (r.bonusesRedeemed || 0);
      });
    });

    const paidReforms = Math.max(0, totalReformed - totalBonusPaid);
    const totalEarned = Math.floor(paidReforms / 15);
    const pendingBonuses = Math.max(0, totalEarned - totalBonusPaid);

    return { 
      totalSent, totalReformed, totalRepaired, totalExchanged, totalFailed,
      totalBonusEarned: totalEarned, totalBonusPaid, pendingBonuses 
    };
  }, [shipments]);

  const allInvoiceNumbers = useMemo(() => {
    const numbers: string[] = [];
    (shipments || []).forEach(s => {
      (s.returns || []).forEach(r => {
        if (r.invoiceNumber) numbers.push(r.invoiceNumber.toLowerCase());
      });
    });
    return numbers;
  }, [shipments]);

  useEffect(() => {
    if (stats.pendingBonuses > lastBonusCount) {
      setShowBonusAlert(true);
      setLastBonusCount(stats.pendingBonuses);
    } else if (stats.pendingBonuses < lastBonusCount) {
      setLastBonusCount(stats.pendingBonuses);
    }
  }, [stats.pendingBonuses, lastBonusCount]);

  const handleLogin = (username: string) => {
    setCurrentUser(username);
    localStorage.setItem(AUTH_KEY, username);
    fetchShipments();
  };

  const handleRegister = async (username: string, password: string): Promise<boolean> => {
    try {
      setSyncStatus('syncing');
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'register', user: { username, password } }),
      });
      setSyncStatus('success');
      await fetchUsers();
      return true;
    } catch (error) {
      setSyncStatus('error');
      return false;
    }
  };

  const handleChangePassword = async (newPassword: string): Promise<boolean> => {
    if (!currentUser) return false;
    try {
      setSyncStatus('syncing');
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'changePassword', user: { username: currentUser, password: newPassword } }),
      });
      setSyncStatus('success');
      await fetchUsers();
      return true;
    } catch (error) {
      setSyncStatus('error');
      return false;
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_KEY);
    setView('dashboard');
  };

  const handleAddShipment = (data: { date: string, quantity: number }) => {
    const newShipment: Shipment = {
      id: crypto.randomUUID(),
      number: `REM-${String(shipments.length + 1).padStart(4, '0')}`,
      sendDate: data.date,
      quantitySent: data.quantity,
      status: ShipmentStatus.AWAITING,
      returns: []
    };
    setShipments([newShipment, ...shipments]);
    setView('dashboard');
  };

  const handleRegisterReturn = (id: string, event: ReturnEvent) => {
    setShipments(prev => prev.map(s => {
      if (s.id === id) {
        const updatedReturns = [...(s.returns || []), event];
        const totalReturnedCount = updatedReturns.reduce((acc, r) => 
          acc + (r.reformed || 0) + (r.repaired || 0) + (r.exchanged || 0) + (r.failed || 0), 0);

        let newStatus = ShipmentStatus.PARTIAL;
        if (totalReturnedCount >= s.quantitySent) {
          newStatus = ShipmentStatus.FINISHED;
        }

        return { ...s, status: newStatus, returns: updatedReturns };
      }
      return s;
    }));
    setView('dashboard');
  };

  const openReturnForm = (id: string) => {
    setActiveShipmentId(id);
    setView('return');
  };

  if (!currentUser) {
    return (
      <Login 
        onLogin={handleLogin} 
        onRegister={handleRegister}
        validUsers={validUsers} 
        isLoading={loadingInitial} 
      />
    );
  }

  return (
    <div className={`min-h-screen ${darkMode ? 'dark bg-slate-900' : 'bg-slate-50'} flex flex-col pb-20 md:pb-0 transition-colors duration-300`}>
      <header className="bg-red-700 dark:bg-red-900 text-white p-4 shadow-lg sticky top-0 z-10">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Disc className="w-7 h-7 animate-spin-slow" />
            <h1 className="text-xl font-bold tracking-tight">Controle de Reformas</h1>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 hover:bg-red-600 dark:hover:bg-red-800 rounded-full transition-colors"
              title={darkMode ? "Modo Claro" : "Modo Escuro"}
            >
              {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            <button 
              onClick={fetchShipments}
              className="p-2 hover:bg-red-600 dark:hover:bg-red-800 rounded-full transition-colors"
              title="Sincronizar Agora"
            >
              <RotateCcw className={`w-5 h-5 ${syncStatus === 'syncing' ? 'animate-spin' : ''}`} />
            </button>

            {syncStatus !== 'idle' && (
              <div className={`flex items-center gap-1 text-[10px] px-2 py-1 rounded-full border ${
                syncStatus === 'syncing' ? 'bg-red-800/50 border-red-400/20 animate-pulse' :
                syncStatus === 'success' ? 'bg-green-500/20 border-green-400/40 text-green-100' :
                'bg-yellow-500/20 border-yellow-400/40 text-yellow-100'
              }`}>
                {syncStatus === 'syncing' && <CloudUpload className="w-3 h-3" />}
                {syncStatus === 'success' && <Check className="w-3 h-3" />}
                {syncStatus === 'error' && <AlertCircle className="w-3 h-3" />}
                <span className="hidden xs:inline">
                  {syncStatus === 'syncing' ? 'Sincronizando...' : 
                   syncStatus === 'success' ? 'Salvo' : 'Erro'}
                </span>
              </div>
            )}

            <div className="flex items-center gap-1">
               <button 
                 onClick={() => setView('settings')}
                 className={`flex items-center gap-2 text-xs font-medium px-3 py-1.5 rounded-full border border-red-400/20 transition-colors ${view === 'settings' ? 'bg-white text-red-700' : 'bg-red-800/50 text-white'}`}
               >
                 <UserIcon className="w-3 h-3" />
                 <span className="hidden xs:inline">{currentUser}</span>
               </button>
            </div>

            <button onClick={handleLogout} className="p-2 hover:bg-red-600 dark:hover:bg-red-800 rounded-full transition-colors text-red-100" title="Sair">
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-4xl w-full mx-auto p-4 animate-in fade-in duration-500">
        {view === 'dashboard' && (
          <Dashboard 
            stats={stats} 
            onNewShipment={() => setView('new')} 
            onViewList={() => setView('list')}
            recentShipments={(shipments || []).slice(0, 5)}
            onOpenReturn={openReturnForm}
          />
        )}

        {view === 'new' && (
          <ShipmentForm onSave={handleAddShipment} onCancel={() => setView('dashboard')} />
        )}

        {view === 'list' && (
          <ShipmentList shipments={shipments || []} onOpenReturn={openReturnForm} onBack={() => setView('dashboard')} />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={(shipments || []).find(s => s.id === activeShipmentId)!}
            pendingBonuses={stats.pendingBonuses}
            existingInvoiceNumbers={allInvoiceNumbers}
            onSave={(event) => handleRegisterReturn(activeShipmentId, event)}
            onCancel={() => setView('dashboard')}
          />
        )}

        {view === 'settings' && (
          <PasswordChange 
            username={currentUser}
            validUsers={validUsers}
            onSave={handleChangePassword}
            onCancel={() => setView('dashboard')}
          />
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700 p-2 md:hidden flex justify-around items-center z-10 transition-colors">
        <button onClick={() => setView('dashboard')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}>
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-xs">Início</span>
        </button>
        <button onClick={() => setView('new')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'new' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}>
          <div className="bg-red-600 dark:bg-red-700 text-white p-2 rounded-full -mt-8 shadow-lg ring-4 ring-slate-50 dark:ring-slate-900 transition-all">
            <Plus className="w-6 h-6" />
          </div>
          <span className="text-xs mt-1">Nova</span>
        </button>
        <button onClick={() => setView('list')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'list' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}>
          <History className="w-6 h-6" />
          <span className="text-xs">Histórico</span>
        </button>
      </nav>

      {showBonusAlert && (
        <BonusNotification availableCount={stats.pendingBonuses} onClose={() => setShowBonusAlert(false)} />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { BarChart3, Trophy, Plus, ArrowRight, Clock, CheckCircle2, Disc, RotateCcw, Gift, AlertCircle, TrendingUp, XCircle, Hammer, RefreshCw } from 'lucide-react';
import { BonusStats, Shipment, ShipmentStatus } from '../types';

interface DashboardProps {
  stats: BonusStats;
  onNewShipment: () => void;
  onViewList: () => void;
  recentShipments: Shipment[];
  onOpenReturn: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, onNewShipment, onViewList, recentShipments, onOpenReturn }) => {
  const paidReforms = Math.max(0, stats.totalReformed - stats.totalBonusPaid);
  const nextBonusProgress = paidReforms % 15;
  const progressPercent = (nextBonusProgress / 15) * 100;

  const totalReturns = stats.totalReformed + stats.totalRepaired + stats.totalExchanged + stats.totalFailed;
  const successRate = totalReturns > 0 ? (stats.totalReformed / totalReturns) * 100 : 0;

  return (
    <div className="space-y-6">
      {/* Primeiras Métricas Principais */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col justify-between transition-colors">
          <div className="bg-blue-100 dark:bg-blue-900/40 p-2 rounded-lg text-blue-600 dark:text-blue-400 w-fit mb-3">
            <RefreshCw className="w-5 h-5" />
          </div>
          <div>
            <p className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase">Reformados</p>
            <p className="text-xl font-black text-slate-800 dark:text-white">{stats.totalReformed}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col justify-between transition-colors">
          <div className="bg-purple-100 dark:bg-purple-900/40 p-2 rounded-lg text-purple-600 dark:text-purple-400 w-fit mb-3">
            <TrendingUp className="w-5 h-5" />
          </div>
          <div>
            <p className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase">Trocados</p>
            <p className="text-xl font-black text-slate-800 dark:text-white">{stats.totalExchanged}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col justify-between transition-colors">
          <div className="bg-amber-100 dark:bg-amber-900/40 p-2 rounded-lg text-amber-600 dark:text-amber-400 w-fit mb-3">
            <Hammer className="w-5 h-5" />
          </div>
          <div>
            <p className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase">Consertados</p>
            <p className="text-xl font-black text-slate-800 dark:text-white">{stats.totalRepaired}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col justify-between transition-colors">
          <div className="bg-red-100 dark:bg-red-900/40 p-2 rounded-lg text-red-600 dark:text-red-400 w-fit mb-3">
            <XCircle className="w-5 h-5" />
          </div>
          <div>
            <p className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase">Sem Reforma</p>
            <p className="text-xl font-black text-slate-800 dark:text-white">{stats.totalFailed}</p>
          </div>
        </div>
      </div>

      {/* Bônus e Meta */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 flex items-center justify-between transition-colors">
           <div className="flex items-center gap-4">
            <div className="bg-yellow-100 dark:bg-yellow-900/40 p-4 rounded-xl text-yellow-600 dark:text-yellow-400">
              <Gift className="w-8 h-8" />
            </div>
            <div>
              <p className="text-sm text-slate-500 dark:text-slate-400 font-medium">Bônus Disponíveis</p>
              <p className="text-3xl font-black dark:text-white">{stats.pendingBonuses}</p>
            </div>
          </div>
          <div className="text-right">
             <p className="text-xs font-bold text-red-600 dark:text-red-400 mb-1">{nextBonusProgress}/15 para o próximo</p>
             <div className="w-32 bg-slate-100 dark:bg-slate-700 h-2 rounded-full overflow-hidden">
                <div 
                  className="bg-red-600 dark:bg-red-500 h-full rounded-full transition-all duration-1000"
                  style={{ width: `${progressPercent}%` }}
                ></div>
             </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 flex items-center gap-4 transition-colors">
          <div className="bg-green-100 dark:bg-green-900/40 p-4 rounded-xl text-green-600 dark:text-green-400">
            <BarChart3 className="w-8 h-8" />
          </div>
          <div className="flex-1">
            <p className="text-sm text-slate-500 dark:text-slate-400 font-medium">Taxa de Aproveitamento</p>
            <div className="flex items-end gap-2">
              <p className="text-3xl font-black dark:text-white">{successRate.toFixed(1)}%</p>
              <p className="text-xs text-slate-400 mb-1">de {totalReturns} retornos</p>
            </div>
          </div>
        </div>
      </div>

      <button 
        onClick={onNewShipment}
        className="w-full bg-red-600 hover:bg-red-700 dark:bg-red-700 dark:hover:bg-red-800 text-white font-bold py-4 px-6 rounded-2xl shadow-md transition-all flex items-center justify-center gap-2 text-lg active:scale-95"
      >
        <Plus className="w-6 h-6" />
        Nova Remessa
      </button>

      {/* Histórico Recente */}
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden transition-colors">
        <div className="p-4 border-b border-slate-50 dark:border-slate-700 flex justify-between items-center">
          <h2 className="font-bold text-slate-700 dark:text-slate-200 uppercase text-xs tracking-widest">Últimas Remessas</h2>
          <button 
            onClick={onViewList}
            className="text-red-600 dark:text-red-400 text-sm font-semibold flex items-center gap-1 hover:underline"
          >
            Ver todas <ArrowRight className="w-4 h-4" />
          </button>
        </div>

        {(!recentShipments || recentShipments.length === 0) ? (
          <div className="p-10 text-center text-slate-400">
            <Disc className="w-12 h-12 mx-auto mb-2 opacity-20" />
            <p>Nenhuma remessa encontrada.</p>
          </div>
        ) : (
          <div className="divide-y divide-slate-50 dark:divide-slate-700">
            {recentShipments.map((shipment) => {
               const totalReturned = (shipment.returns || []).reduce((sum, r) => sum + (r.reformed || 0) + (r.repaired || 0) + (r.exchanged || 0) + (r.failed || 0), 0);

               let statusStyles = "bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400";
               let StatusIcon = AlertCircle;

               if (shipment.status === ShipmentStatus.PARTIAL) {
                 statusStyles = "bg-yellow-100 text-yellow-600 dark:bg-yellow-900/30 dark:text-yellow-400";
                 StatusIcon = Clock;
               } else if (shipment.status === ShipmentStatus.FINISHED) {
                 statusStyles = "bg-green-100 text-green-600 dark:bg-green-900/30 dark:text-green-400";
                 StatusIcon = CheckCircle2;
               }

               return (
                <div key={shipment.id} className="p-4 flex items-center justify-between hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-full ${statusStyles}`}>
                      <StatusIcon className="w-5 h-5" />
                    </div>
                    <div>
                      <p className="font-bold text-slate-800 dark:text-slate-200">{shipment.number}</p>
                      <p className="text-xs text-slate-500 dark:text-slate-400">{shipment.sendDate ? new Date(shipment.sendDate).toLocaleDateString() : 'N/A'}</p>
                    </div>
                  </div>

                  <div className="flex items-center gap-4">
                    <div className="text-right hidden sm:block">
                      <p className="text-sm font-semibold text-slate-700 dark:text-slate-300">{totalReturned} / {shipment.quantitySent} pneus</p>
                      <p className={`text-[10px] font-black uppercase ${
                        shipment.status === ShipmentStatus.AWAITING ? 'text-red-500' : 
                        shipment.status === ShipmentStatus.PARTIAL ? 'text-yellow-600' : 'text-green-500'
                      }`}>
                        {shipment.status}
                      </p>
                    </div>
                    {shipment.status !== ShipmentStatus.FINISHED && (
                      <button 
                        onClick={() => onOpenReturn(shipment.id)}
                        className="bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 text-slate-700 dark:text-slate-300 p-2 rounded-xl transition-colors active:scale-95"
                      >
                        <RotateCcw className="w-5 h-5" />
                      </button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { ChevronLeft, RotateCcw, Clock, CheckCircle2, History, ChevronDown, ChevronUp, FileText, Gift, AlertCircle } from 'lucide-react';
import { Shipment, ShipmentStatus } from '../types';

interface ShipmentListProps {
  shipments: Shipment[];
  onOpenReturn: (id: string) => void;
  onBack: () => void;
}

const ShipmentList: React.FC<ShipmentListProps> = ({ shipments, onOpenReturn, onBack }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4 mb-2">
        <button 
          onClick={onBack}
          className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-full transition-colors"
        >
          <ChevronLeft className="w-6 h-6 text-slate-600 dark:text-slate-400" />
        </button>
        <h2 className="text-xl font-bold text-slate-700 dark:text-slate-200">Histórico de Remessas</h2>
      </div>

      {(!shipments || shipments.length === 0) ? (
        <div className="bg-white dark:bg-slate-800 rounded-2xl p-12 text-center text-slate-400 dark:text-slate-500 shadow-sm border border-slate-100 dark:border-slate-700">
          <History className="w-16 h-16 mx-auto mb-4 opacity-10" />
          <p className="text-lg">Nenhuma remessa registrada ainda.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {shipments.map((s) => {
            const returns = s.returns || [];
            const totalReturned = returns.reduce((sum, r) => sum + (r.reformed || 0) + (r.repaired || 0) + (r.exchanged || 0) + (r.failed || 0), 0);
            const isExpanded = expandedId === s.id;
            const progressPercent = Math.min(100, (totalReturned / (s.quantitySent || 1)) * 100);

            let dotColor = "bg-red-500";
            let statusTextColor = "text-red-500";

            if (s.status === ShipmentStatus.PARTIAL) {
              dotColor = "bg-yellow-400";
              statusTextColor = "text-yellow-600 dark:text-yellow-500";
            } else if (s.status === ShipmentStatus.FINISHED) {
              dotColor = "bg-green-500";
              statusTextColor = "text-green-500 dark:text-green-400";
            }

            return (
              <div key={s.id} className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden transition-colors">
                <div className="p-4 cursor-pointer" onClick={() => toggleExpand(s.id)}>
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex items-center gap-2">
                      <div className={`w-3 h-3 rounded-full ${dotColor}`}></div>
                      <span className={`text-[10px] font-black uppercase ${statusTextColor}`}>{s.status}</span>
                    </div>
                    <span className="text-xs font-medium text-slate-400 dark:text-slate-500">{s.sendDate ? new Date(s.sendDate).toLocaleDateString() : 'N/A'}</span>
                  </div>

                  <div className="flex justify-between items-center">
                    <div>
                      <h3 className="text-lg font-black text-slate-800 dark:text-slate-100 leading-tight">{s.number}</h3>
                      <p className="text-sm font-bold text-slate-500 dark:text-slate-400">{totalReturned} / {s.quantitySent} Pneus</p>
                    </div>

                    <div className="flex items-center gap-2">
                      {s.status !== ShipmentStatus.FINISHED && (
                        <button 
                          onClick={(e) => { e.stopPropagation(); onOpenReturn(s.id); }}
                          className="bg-red-600 dark:bg-red-700 hover:bg-red-700 dark:hover:bg-red-800 text-white p-2 rounded-xl shadow-md active:scale-95 transition-all"
                        >
                          <RotateCcw className="w-5 h-5" />
                        </button>
                      )}
                      <div className="p-1 text-slate-400 dark:text-slate-500">
                        {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                      </div>
                    </div>
                  </div>

                  <div className="mt-3 w-full bg-slate-100 dark:bg-slate-700 h-1.5 rounded-full overflow-hidden">
                    <div 
                      className={`h-full rounded-full transition-all duration-500 ${
                        s.status === ShipmentStatus.FINISHED ? 'bg-green-500' : 
                        s.status === ShipmentStatus.PARTIAL ? 'bg-yellow-400' : 'bg-red-500'
                      }`}
                      style={{ width: `${progressPercent}%` }}
                    ></div>
                  </div>
                </div>

                {isExpanded && returns.length > 0 && (
                  <div className="bg-slate-50 dark:bg-slate-900/50 p-4 border-t border-slate-100 dark:border-slate-700 space-y-3 animate-in slide-in-from-top-2 duration-200">
                    <h4 className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Retornos Registrados</h4>
                    {returns.map((r) => (
                      <div key={r.id} className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                        <div className="flex justify-between items-center mb-2 border-b border-slate-50 dark:border-slate-700 pb-2">
                          <div className="flex items-center gap-2">
                            <FileText className="w-3 h-3 text-red-500" />
                            <span className="text-xs font-bold text-slate-700 dark:text-slate-200">{r.invoiceNumber || 'S/N'}</span>
                            {r.bonusesRedeemed && r.bonusesRedeemed > 0 && (
                                <span className="bg-yellow-100 dark:bg-yellow-900/40 text-yellow-700 dark:text-yellow-400 text-[8px] font-black px-1.5 py-0.5 rounded-full flex items-center gap-0.5 uppercase">
                                    <Gift className="w-2 h-2" /> {r.bonusesRedeemed} {r.bonusesRedeemed === 1 ? 'Bônus Utilizado' : 'Bônus Utilizados'}
                                </span>
                            )}
                          </div>
                          <span className="text-[10px] font-medium text-slate-400 dark:text-slate-500">{r.date ? new Date(r.date).toLocaleDateString() : 'N/A'}</span>
                        </div>
                        <div className="grid grid-cols-4 gap-1 text-center">
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">Ref</p>
                            <p className="text-sm font-bold text-green-600 dark:text-green-400">{r.reformed || 0}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">Cons</p>
                            <p className="text-sm font-bold text-red-600 dark:text-red-400">{r.repaired || 0}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">Troc</p>
                            <p className="text-sm font-bold text-purple-600 dark:text-purple-400">{r.exchanged || 0}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">S/R</p>
                            <p className="text-sm font-bold text-red-900 dark:text-red-300">{r.failed || 0}</p>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default ShipmentList;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { 
  Disc, 
  RotateCcw, 
  Plus, 
  BarChart3, 
  CheckCircle2, 
  Clock, 
  ChevronRight, 
  AlertCircle,
  Trophy,
  History,
  LayoutDashboard,
  LogOut,
  User as UserIcon,
  PieChart,
  Gift,
  CloudUpload,
  Check,
  Moon,
  Sun,
  Settings
} from 'lucide-react';
import { Shipment, ShipmentStatus, ReturnEvent, BonusStats } from './types';
import Dashboard from './components/Dashboard';
import ShipmentList from './components/ShipmentList';
import ShipmentForm from './components/ShipmentForm';
import ReturnForm from './components/ReturnForm';
import BonusNotification from './components/BonusNotification';
import Login from './components/Login';
import PasswordChange from './components/PasswordChange';

const STORAGE_KEY = 'pneucontrol_data_v3';
const AUTH_KEY = 'pneucontrol_user';
const THEME_KEY = 'pneucontrol_theme';
// URL DO SEU GOOGLE APPS SCRIPT (Certifique-se de implantar como "Qualquer pessoa")
const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbzpXLsLVFn0ULlwo-fU49lJRm3KW7EQHqxxH1BSQ7tXGh8K8dRIMm1stJ2MBTqt5B8/exec';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<string | null>(null);
  const [validUsers, setValidUsers] = useState<{username: string, password: string}[]>([]);
  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [view, setView] = useState<'dashboard' | 'new' | 'list' | 'return' | 'settings'>('dashboard');
  const [activeShipmentId, setActiveShipmentId] = useState<string | null>(null);
  const [showBonusAlert, setShowBonusAlert] = useState(false);
  const [lastBonusCount, setLastBonusCount] = useState(0);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [loadingInitial, setLoadingInitial] = useState(true);
  const [hasLoadedFromDB, setHasLoadedFromDB] = useState(false); // TRAVA DE SEGURANÇA
  const [darkMode, setDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved === 'dark';
  });

  const fetchUsers = useCallback(async () => {
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getUsers&t=${Date.now()}`);
      if (!response.ok) throw new Error("Erro na resposta do servidor");
      const data = await response.json();
      if (Array.isArray(data)) setValidUsers(data);
    } catch (error) {
      console.warn("Usando lista de usuários padrão:", error);
      setValidUsers([
        { username: "Éder", password: "1" },
        { username: "Wender", password: "1" },
        { username: "Kesley", password: "1" },
        { username: "Roberto", password: "1" }
      ]);
    }
  }, []);

  const fetchShipments = useCallback(async () => {
    try {
      setSyncStatus('syncing');
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getShipments&t=${Date.now()}`);
      if (!response.ok) throw new Error("Erro na busca de dados");
      const data = await response.json();

      let incomingShipments: Shipment[] = [];
      if (data && Array.isArray(data.shipments)) {
        incomingShipments = data.shipments;
      } else if (data && Array.isArray(data)) {
        incomingShipments = data;
      }

      // Se o servidor retornou dados, atualizamos o estado e liberamos a trava
      if (incomingShipments.length > 0) {
        setShipments(incomingShipments);
        setHasLoadedFromDB(true);
        setSyncStatus('success');
      } else {
        // Se o banco estiver realmente vazio (ex: novo projeto), liberamos a trava também
        setHasLoadedFromDB(true);
        setSyncStatus('idle');
      }
    } catch (error) {
      console.error("Erro ao buscar histórico do servidor:", error);
      setSyncStatus('error');
      // Tenta carregar do cache local apenas se falhar a rede
      const savedData = localStorage.getItem(STORAGE_KEY);
      if (savedData) {
        try {
          const parsed = JSON.parse(savedData);
          if (Array.isArray(parsed)) {
            setShipments(parsed);
            // NÃO liberamos hasLoadedFromDB aqui para não sobrescrever o banco com cache possivelmente antigo
          }
        } catch (e) { console.error(e); }
      }
    } finally {
      setLoadingInitial(false);
      setTimeout(() => setSyncStatus('idle'), 2000);
    }
  }, []);

  useEffect(() => {
    const init = async () => {
      const savedUser = localStorage.getItem(AUTH_KEY);
      if (savedUser) setCurrentUser(savedUser);

      const savedData = localStorage.getItem(STORAGE_KEY);
      if (savedData) {
        try { setShipments(JSON.parse(savedData)); } catch(e){}
      }

      await fetchUsers();
      await fetchShipments();
    };
    init();
  }, [fetchUsers, fetchShipments]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, darkMode ? 'dark' : 'light');
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Efeito de sincronização: SÓ ENVIA SE JÁ TIVER CARREGADO DO BANCO
  useEffect(() => {
    if (loadingInitial || !hasLoadedFromDB) return;

    localStorage.setItem(STORAGE_KEY, JSON.stringify(shipments));

    const syncWithSheets = async () => {
      setSyncStatus('syncing');
      try {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: 'POST',
          mode: 'no-cors', // Necessário para Google Apps Script
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'syncShipments', shipments }),
        });
        setSyncStatus('success');
        setTimeout(() => setSyncStatus('idle'), 3000);
      } catch (error) {
        console.error("Erro ao sincronizar:", error);
        setSyncStatus('error');
      }
    };

    const timeoutId = setTimeout(syncWithSheets, 1500); 
    return () => clearTimeout(timeoutId);
  }, [shipments, loadingInitial, hasLoadedFromDB]);

  const stats: BonusStats = useMemo(() => {
    let totalSent = 0;
    let totalReformed = 0;
    let totalRepaired = 0;
    let totalExchanged = 0;
    let totalFailed = 0;
    let totalBonusPaid = 0;

    (shipments || []).forEach(s => {
      totalSent += (s.quantitySent || 0);
      (s.returns || []).forEach(r => {
        totalReformed += (r.reformed || 0);
        totalRepaired += (r.repaired || 0);
        totalExchanged += (r.exchanged || 0);
        totalFailed += (r.failed || 0);
        totalBonusPaid += (r.bonusesRedeemed || 0);
      });
    });

    const paidReforms = Math.max(0, totalReformed - totalBonusPaid);
    const totalEarned = Math.floor(paidReforms / 15);
    const pendingBonuses = Math.max(0, totalEarned - totalBonusPaid);

    return { 
      totalSent, totalReformed, totalRepaired, totalExchanged, totalFailed,
      totalBonusEarned: totalEarned, totalBonusPaid, pendingBonuses 
    };
  }, [shipments]);

  const allInvoiceNumbers = useMemo(() => {
    const numbers: string[] = [];
    (shipments || []).forEach(s => {
      (s.returns || []).forEach(r => {
        if (r.invoiceNumber) numbers.push(r.invoiceNumber.toLowerCase());
      });
    });
    return numbers;
  }, [shipments]);

  useEffect(() => {
    if (stats.pendingBonuses > lastBonusCount) {
      setShowBonusAlert(true);
      setLastBonusCount(stats.pendingBonuses);
    } else if (stats.pendingBonuses < lastBonusCount) {
      setLastBonusCount(stats.pendingBonuses);
    }
  }, [stats.pendingBonuses, lastBonusCount]);

  const handleLogin = (username: string) => {
    setCurrentUser(username);
    localStorage.setItem(AUTH_KEY, username);
    fetchShipments(); // Puxa dados frescos no login
  };

  const handleRegister = async (username: string, password: string): Promise<boolean> => {
    try {
      setSyncStatus('syncing');
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'register', user: { username, password } }),
      });
      setSyncStatus('success');
      await fetchUsers();
      return true;
    } catch (error) {
      setSyncStatus('error');
      return false;
    }
  };

  const handleChangePassword = async (newPassword: string): Promise<boolean> => {
    if (!currentUser) return false;
    try {
      setSyncStatus('syncing');
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'changePassword', user: { username: currentUser, password: newPassword } }),
      });
      setSyncStatus('success');
      await fetchUsers();
      return true;
    } catch (error) {
      setSyncStatus('error');
      return false;
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_KEY);
    setView('dashboard');
  };

  const handleAddShipment = (data: { date: string, quantity: number }) => {
    const newShipment: Shipment = {
      id: crypto.randomUUID(),
      number: `REM-${String(shipments.length + 1).padStart(4, '0')}`,
      sendDate: data.date,
      quantitySent: data.quantity,
      status: ShipmentStatus.AWAITING,
      returns: []
    };
    setShipments(prev => [newShipment, ...prev]);
    setView('dashboard');
  };

  const handleRegisterReturn = (id: string, event: ReturnEvent) => {
    setShipments(prev => prev.map(s => {
      if (s.id === id) {
        const updatedReturns = [...(s.returns || []), event];
        const totalReturnedCount = updatedReturns.reduce((acc, r) => 
          acc + (r.reformed || 0) + (r.repaired || 0) + (r.exchanged || 0) + (r.failed || 0), 0);

        let newStatus = ShipmentStatus.PARTIAL;
        if (totalReturnedCount >= s.quantitySent) {
          newStatus = ShipmentStatus.FINISHED;
        }

        return { ...s, status: newStatus, returns: updatedReturns };
      }
      return s;
    }));
    setView('dashboard');
  };

  const openReturnForm = (id: string) => {
    setActiveShipmentId(id);
    setView('return');
  };

  if (!currentUser) {
    return (
      <Login 
        onLogin={handleLogin} 
        onRegister={handleRegister}
        validUsers={validUsers} 
        isLoading={loadingInitial} 
      />
    );
  }

  return (
    <div className={`min-h-screen ${darkMode ? 'dark bg-slate-900' : 'bg-slate-50'} flex flex-col pb-20 md:pb-0 transition-colors duration-300`}>
      <header className="bg-red-700 dark:bg-red-900 text-white p-4 shadow-lg sticky top-0 z-10">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Disc className="w-7 h-7 animate-spin-slow" />
            <h1 className="text-xl font-bold tracking-tight">Controle de Reformas</h1>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 hover:bg-red-600 dark:hover:bg-red-800 rounded-full transition-colors"
              title={darkMode ? "Modo Claro" : "Modo Escuro"}
            >
              {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            <button 
              onClick={fetchShipments}
              className="p-2 hover:bg-red-600 dark:hover:bg-red-800 rounded-full transition-colors"
              title="Sincronizar Agora"
            >
              <RotateCcw className={`w-5 h-5 ${syncStatus === 'syncing' ? 'animate-spin' : ''}`} />
            </button>

            {syncStatus !== 'idle' && (
              <div className={`flex items-center gap-1 text-[10px] px-2 py-1 rounded-full border ${
                syncStatus === 'syncing' ? 'bg-red-800/50 border-red-400/20 animate-pulse' :
                syncStatus === 'success' ? 'bg-green-500/20 border-green-400/40 text-green-100' :
                'bg-yellow-500/20 border-yellow-400/40 text-yellow-100'
              }`}>
                {syncStatus === 'syncing' && <CloudUpload className="w-3 h-3" />}
                {syncStatus === 'success' && <Check className="w-3 h-3" />}
                {syncStatus === 'error' && <AlertCircle className="w-3 h-3" />}
                <span className="hidden xs:inline">
                  {syncStatus === 'syncing' ? 'Sincronizando...' : 
                   syncStatus === 'success' ? 'Salvo' : 'Erro'}
                </span>
              </div>
            )}

            <div className="flex items-center gap-1">
               <button 
                 onClick={() => setView('settings')}
                 className={`flex items-center gap-2 text-xs font-medium px-3 py-1.5 rounded-full border border-red-400/20 transition-colors ${view === 'settings' ? 'bg-white text-red-700' : 'bg-red-800/50 text-white'}`}
               >
                 <UserIcon className="w-3 h-3" />
                 <span className="hidden xs:inline">{currentUser}</span>
               </button>
            </div>

            <button onClick={handleLogout} className="p-2 hover:bg-red-600 dark:hover:bg-red-800 rounded-full transition-colors text-red-100" title="Sair">
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-4xl w-full mx-auto p-4 animate-in fade-in duration-500">
        {view === 'dashboard' && (
          <Dashboard 
            stats={stats} 
            onNewShipment={() => setView('new')} 
            onViewList={() => setView('list')}
            recentShipments={(shipments || []).slice(0, 5)}
            onOpenReturn={openReturnForm}
          />
        )}

        {view === 'new' && (
          <ShipmentForm onSave={handleAddShipment} onCancel={() => setView('dashboard')} />
        )}

        {view === 'list' && (
          <ShipmentList shipments={shipments || []} onOpenReturn={openReturnForm} onBack={() => setView('dashboard')} />
        )}

        {view === 'return' && activeShipmentId && (
          <ReturnForm 
            shipment={(shipments || []).find(s => s.id === activeShipmentId)!}
            pendingBonuses={stats.pendingBonuses}
            existingInvoiceNumbers={allInvoiceNumbers}
            onSave={(event) => handleRegisterReturn(activeShipmentId, event)}
            onCancel={() => setView('dashboard')}
          />
        )}

        {view === 'settings' && (
          <PasswordChange 
            username={currentUser}
            validUsers={validUsers}
            onSave={handleChangePassword}
            onCancel={() => setView('dashboard')}
          />
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700 p-2 md:hidden flex justify-around items-center z-10 transition-colors">
        <button onClick={() => setView('dashboard')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}>
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-xs">Início</span>
        </button>
        <button onClick={() => setView('new')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'new' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}>
          <div className="bg-red-600 dark:bg-red-700 text-white p-2 rounded-full -mt-8 shadow-lg ring-4 ring-slate-50 dark:ring-slate-900 transition-all">
            <Plus className="w-6 h-6" />
          </div>
          <span className="text-xs mt-1">Nova</span>
        </button>
        <button onClick={() => setView('list')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'list' ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}>
          <History className="w-6 h-6" />
          <span className="text-xs">Histórico</span>
        </button>
      </nav>

      {showBonusAlert && (
        <BonusNotification availableCount={stats.pendingBonuses} onClose={() => setShowBonusAlert(false)} />
      )}
    </div>
  );
};

export default App;

