Aqui está o código completo e atualizado para o seu **Google Apps Script**. 

Este código é o "motor" que roda por trás da sua planilha Google, permitindo que o aplicativo salve e leia os dados de usuários e o histórico de remessas sem riscos de perda de dados.

### Como Instalar:
1. Abra sua Planilha Google.
2. Vá em **Extensões** > **Apps Script**.
3. Apague qualquer código que esteja lá e cole o código abaixo.
4. Clique no ícone de disquete (**Salvar**) e dê o nome de "Backend PneuControl".
5. Clique no botão azul **Implantar** > **Nova implantação**.
6. Selecione o tipo **App da Web**.
7. Em "Quem pode acessar", selecione **Qualquer pessoa**.
8. Clique em **Implantar**, autorize as permissões e copie a **URL do App da Web** gerada para colocar na variável `GOOGLE_SCRIPT_URL` no seu arquivo `App.tsx`.

```javascript
/**
 * GOOGLE APPS SCRIPT PARA CONTROLE DE REFORMAS
 * Este script gerencia a persistência de dados entre o Web App e o Google Sheets.
 */

const SPREADSHEET_ID = SpreadsheetApp.getActiveSpreadsheet().getId();

/**
 * Gerencia as requisições de LEITURA (GET)
 */
function doGet(e) {
  const action = e.parameter.action;
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  // Ação para buscar lista de usuários cadastrados
  if (action === 'getUsers') {
    const sheet = getOrCreateSheet(ss, "Users");
    const data = sheet.getDataRange().getValues();
    const users = [];
    // Pula o cabeçalho (i=1)
    for(let i = 1; i < data.length; i++) {
      if (data[i][0]) { // Verifica se o nome do usuário não está vazio
        users.push({ username: data[i][0], password: String(data[i][1]) });
      }
    }
    return createResponse(users);
  }

  // Ação para buscar o histórico de remessas
  if (action === 'getShipments') {
    const sheet = getOrCreateSheet(ss, "Shipments");
    const val = sheet.getRange("A1").getValue();
    try {
      // O histórico é armazenado como uma string JSON na célula A1 para performance e estrutura
      const shipments = val ? JSON.parse(val) : [];
      return createResponse({ shipments: shipments });
    } catch(err) {
      // Se houver erro de parse, retorna array vazio para não quebrar o app
      return createResponse({ shipments: [] });
    }
  }
}

/**
 * Gerencia as requisições de ESCRITA (POST)
 */
function doPost(e) {
  let postData;
  try {
    postData = JSON.parse(e.postData.contents);
  } catch(err) {
    return createResponse({ success: false, error: "JSON inválido" });
  }

  const action = postData.action;
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  // Sincroniza todo o histórico de remessas
  if (action === 'syncShipments') {
    const sheet = getOrCreateSheet(ss, "Shipments");
    // Salva o array completo como string JSON na célula A1
    sheet.getRange("A1").setValue(JSON.stringify(postData.shipments));
    return createResponse({ success: true });
  }

  // Cadastra um novo usuário
  if (action === 'register') {
    const sheet = getOrCreateSheet(ss, "Users");
    sheet.appendRow([postData.user.username, String(postData.user.password)]);
    return createResponse({ success: true });
  }

  // Altera a senha de um usuário existente
  if (action === 'changePassword') {
    const sheet = getOrCreateSheet(ss, "Users");
    const data = sheet.getDataRange().getValues();
    let found = false;
    for(let i = 1; i < data.length; i++) {
      if(data[i][0] === postData.user.username) {
        sheet.getRange(i + 1, 2).setValue(String(postData.user.password));
        found = true;
        break;
      }
    }
    return createResponse({ success: found });
  }

  return createResponse({ success: false, error: "Ação não reconhecida" });
}

/**
 * Helper para garantir que as abas necessárias existam na planilha
 */
function getOrCreateSheet(ss, name) {
  let sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    if(name === "Users") {
      sheet.appendRow(["Username", "Password"]);
    }
  }
  return sheet;
}

/**
 * Helper para criar a resposta JSON correta para o Web App
 */
function createResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

