import React, { useState } from 'react';
import { Disc, Lock, User, AlertCircle, Loader2, UserPlus, LogIn } from 'lucide-react';

interface LoginProps {
  onLogin: (username: string) => void;
  onRegister: (username: string, password: string) => Promise<boolean>;
  validUsers: { username: string, password: string }[];
  isLoading: boolean;
  darkMode?: boolean;
}

const Login: React.FC<LoginProps> = ({ onLogin, onRegister, validUsers, isLoading, darkMode }) => {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (mode === 'register') {
      if (password !== confirmPassword) {
        setError('As senhas não coincidem.');
        return;
      }
      if (password.length < 4) {
        setError('A senha deve ter pelo menos 4 caracteres.');
        return;
      }

      const userExists = validUsers.some(u => u.username.toLowerCase() === username.trim().toLowerCase());
      if (userExists) {
        setError('Este nome de usuário já está em uso.');
        return;
      }

      setIsProcessing(true);
      const success = await onRegister(username.trim(), password);
      setIsProcessing(false);

      if (success) {
        setMode('login');
        setError(null);
        alert('Cadastro realizado com sucesso! Agora você pode entrar.');
      } else {
        setError('Ocorreu um erro ao tentar cadastrar. Tente novamente.');
      }
    } else {
      // Garantir comparação de tipos string
      const user = validUsers.find(
        (u) => u.username.toLowerCase() === username.trim().toLowerCase() && String(u.password) === String(password)
      );

      if (user) {
        onLogin(user.username);
      } else {
        setError('Usuário ou senha inválidos.');
      }
    }
  };

  const toggleMode = () => {
    setMode(mode === 'login' ? 'register' : 'login');
    setError(null);
    setPassword('');
    setConfirmPassword('');
  };

  return (
    <div className={`min-h-screen ${darkMode ? 'dark bg-slate-900' : 'bg-slate-50'} flex flex-col items-center justify-center p-6 transition-colors duration-300`}>
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-20 h-20 bg-red-600 text-white rounded-3xl shadow-xl shadow-red-200 dark:shadow-red-900/20 mb-4 animate-in fade-in slide-in-from-top-4 duration-700">
            <Disc className="w-10 h-10 animate-spin-slow" />
          </div>
          <h1 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Controle de Reformas</h1>
          <p className="text-slate-500 dark:text-slate-400 font-medium mt-2">Gestão de Manutenção e Bônus</p>
        </div>

        <div className="bg-white dark:bg-slate-800 p-8 rounded-3xl shadow-xl shadow-slate-200/60 dark:shadow-black/40 border border-slate-100 dark:border-slate-700 animate-in zoom-in-95 duration-500">
          <h2 className="text-xl font-bold text-slate-800 dark:text-white mb-6">
            {mode === 'login' ? 'Acesse sua conta' : 'Criar nova conta'}
          </h2>

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <label className="block text-sm font-bold text-slate-600 dark:text-slate-400 mb-2">Usuário</label>
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 dark:text-slate-500" />
                <input 
                  type="text"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="Seu nome de usuário"
                  className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl p-4 pl-12 text-slate-800 dark:text-white focus:ring-2 focus:ring-red-500 transition-all outline-none"
                  required
                  disabled={isLoading || isProcessing}
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-600 dark:text-slate-400 mb-2">Senha</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 dark:text-slate-500" />
                <input 
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl p-4 pl-12 text-slate-800 dark:text-white focus:ring-2 focus:ring-red-500 transition-all outline-none"
                  required
                  disabled={isLoading || isProcessing}
                />
              </div>
            </div>

            {mode === 'register' && (
              <div className="animate-in slide-in-from-top-2 duration-300">
                <label className="block text-sm font-bold text-slate-600 dark:text-slate-400 mb-2">Confirmar Senha</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 dark:text-slate-500" />
                  <input 
                    type="password"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    placeholder="••••••••"
                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl p-4 pl-12 text-slate-800 dark:text-white focus:ring-2 focus:ring-red-500 transition-all outline-none"
                    required
                    disabled={isLoading || isProcessing}
                  />
                </div>
              </div>
            )}

            {error && (
              <div className="flex items-center gap-2 text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 p-3 rounded-xl animate-in shake duration-300">
                <AlertCircle className="w-5 h-5 shrink-0" />
                <p className="text-sm font-bold">{error}</p>
              </div>
            )}

            <button 
              type="submit"
              disabled={isLoading || isProcessing}
              className="w-full bg-red-600 hover:bg-red-700 dark:bg-red-700 dark:hover:bg-red-800 text-white font-bold py-4 rounded-2xl shadow-lg shadow-red-200 dark:shadow-none transition-all active:scale-95 disabled:bg-slate-300 dark:disabled:bg-slate-700 disabled:shadow-none flex items-center justify-center gap-2"
            >
              {(isLoading || isProcessing) ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" />
                  {isProcessing ? 'Cadastrando...' : 'Carregando...'}
                </>
              ) : (
                mode === 'login' ? (
                  <><LogIn className="w-5 h-5" /> Entrar no Sistema</>
                ) : (
                  <><UserPlus className="w-5 h-5" /> Criar Conta</>
                )
              )}
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-50 dark:border-slate-700 text-center">
            <button 
              onClick={toggleMode}
              className="text-red-600 dark:text-red-400 text-sm font-bold hover:underline transition-all"
            >
              {mode === 'login' ? 'Não tem conta? Cadastre-se' : 'Já possui conta? Faça login'}
            </button>
            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-medium mt-6 uppercase tracking-widest">
              &copy; {new Date().getFullYear()} Controle de Reformas
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { ChevronLeft, RotateCcw, Clock, CheckCircle2, History, ChevronDown, ChevronUp, FileText, Gift, AlertCircle } from 'lucide-react';
import { Shipment, ShipmentStatus } from '../types';

interface ShipmentListProps {
  shipments: Shipment[];
  onOpenReturn: (id: string) => void;
  onBack: () => void;
}

const ShipmentList: React.FC<ShipmentListProps> = ({ shipments, onOpenReturn, onBack }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4 mb-2">
        <button 
          onClick={onBack}
          className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-full transition-colors"
        >
          <ChevronLeft className="w-6 h-6 text-slate-600 dark:text-slate-400" />
        </button>
        <h2 className="text-xl font-bold text-slate-700 dark:text-slate-200">Histórico de Remessas</h2>
      </div>

      {(shipments || []).length === 0 ? (
        <div className="bg-white dark:bg-slate-800 rounded-2xl p-12 text-center text-slate-400 dark:text-slate-500 shadow-sm border border-slate-100 dark:border-slate-700">
          <History className="w-16 h-16 mx-auto mb-4 opacity-10" />
          <p className="text-lg">Nenhuma remessa registrada ainda.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {shipments.map((s) => {
            // Correção defensiva: Garante que returns seja array antes de chamar reduce
            const returns = Array.isArray(s.returns) ? s.returns : [];
            const totalReturned = returns.reduce((sum, r) => sum + (r.reformed || 0) + (r.repaired || 0) + (r.exchanged || 0) + (r.failed || 0), 0);
            const isExpanded = expandedId === s.id;
            const progressPercent = Math.min(100, (totalReturned / s.quantitySent) * 100);

            let dotColor = "bg-red-500";
            let statusTextColor = "text-red-500";

            if (s.status === ShipmentStatus.PARTIAL) {
              dotColor = "bg-yellow-400";
              statusTextColor = "text-yellow-600 dark:text-yellow-500";
            } else if (s.status === ShipmentStatus.FINISHED) {
              dotColor = "bg-green-500";
              statusTextColor = "text-green-500 dark:text-green-400";
            }

            return (
              <div key={s.id} className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden transition-colors">
                <div className="p-4 cursor-pointer" onClick={() => toggleExpand(s.id)}>
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex items-center gap-2">
                      <div className={`w-3 h-3 rounded-full ${dotColor}`}></div>
                      <span className={`text-[10px] font-black uppercase ${statusTextColor}`}>{s.status}</span>
                    </div>
                    <span className="text-xs font-medium text-slate-400 dark:text-slate-500">{new Date(s.sendDate).toLocaleDateString()}</span>
                  </div>

                  <div className="flex justify-between items-center">
                    <div>
                      <h3 className="text-lg font-black text-slate-800 dark:text-slate-100 leading-tight">{s.number}</h3>
                      <p className="text-sm font-bold text-slate-500 dark:text-slate-400">{totalReturned} / {s.quantitySent} Pneus</p>
                    </div>

                    <div className="flex items-center gap-2">
                      {s.status !== ShipmentStatus.FINISHED && (
                        <button 
                          onClick={(e) => { e.stopPropagation(); onOpenReturn(s.id); }}
                          className="bg-red-600 dark:bg-red-700 hover:bg-red-700 dark:hover:bg-red-800 text-white p-2 rounded-xl shadow-md active:scale-95 transition-all"
                        >
                          <RotateCcw className="w-5 h-5" />
                        </button>
                      )}
                      <div className="p-1 text-slate-400 dark:text-slate-500">
                        {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                      </div>
                    </div>
                  </div>

                  <div className="mt-3 w-full bg-slate-100 dark:bg-slate-700 h-1.5 rounded-full overflow-hidden">
                    <div 
                      className={`h-full rounded-full transition-all duration-500 ${
                        s.status === ShipmentStatus.FINISHED ? 'bg-green-500' : 
                        s.status === ShipmentStatus.PARTIAL ? 'bg-yellow-400' : 'bg-red-500'
                      }`}
                      style={{ width: `${progressPercent}%` }}
                    ></div>
                  </div>
                </div>

                {isExpanded && returns.length > 0 && (
                  <div className="bg-slate-50 dark:bg-slate-900/50 p-4 border-t border-slate-100 dark:border-slate-700 space-y-3 animate-in slide-in-from-top-2 duration-200">
                    <h4 className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Retornos Registrados</h4>
                    {returns.map((r) => (
                      <div key={r.id} className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                        <div className="flex justify-between items-center mb-2 border-b border-slate-50 dark:border-slate-700 pb-2">
                          <div className="flex items-center gap-2">
                            <FileText className="w-3 h-3 text-red-500" />
                            <span className="text-xs font-bold text-slate-700 dark:text-slate-200">{r.invoiceNumber}</span>
                            {r.bonusesRedeemed && r.bonusesRedeemed > 0 && (
                                <span className="bg-yellow-100 dark:bg-yellow-900/40 text-yellow-700 dark:text-yellow-400 text-[8px] font-black px-1.5 py-0.5 rounded-full flex items-center gap-0.5 uppercase">
                                    <Gift className="w-2 h-2" /> {r.bonusesRedeemed} {r.bonusesRedeemed === 1 ? 'Bônus Utilizado' : 'Bônus Utilizados'}
                                </span>
                            )}
                          </div>
                          <span className="text-[10px] font-medium text-slate-400 dark:text-slate-500">{new Date(r.date).toLocaleDateString()}</span>
                        </div>
                        <div className="grid grid-cols-4 gap-1 text-center">
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">Ref</p>
                            <p className="text-sm font-bold text-green-600 dark:text-green-400">{r.reformed}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">Cons</p>
                            <p className="text-sm font-bold text-red-600 dark:text-red-400">{r.repaired}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">Troc</p>
                            <p className="text-sm font-bold text-purple-600 dark:text-purple-400">{r.exchanged}</p>
                          </div>
                          <div>
                            <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">S/R</p>
                            <p className="text-sm font-bold text-red-900 dark:text-red-300">{r.failed}</p>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default ShipmentList;

import React from 'react';
import { BarChart3, Trophy, Plus, ArrowRight, Clock, CheckCircle2, Disc, RotateCcw, Gift, AlertCircle, TrendingUp, XCircle, Hammer, RefreshCw, CheckCircle } from 'lucide-react';
import { BonusStats, Shipment, ShipmentStatus } from '../types';

interface DashboardProps {
  stats: BonusStats;
  onNewShipment: () => void;
  onViewList: () => void;
  recentShipments: Shipment[];
