---

### 2. Código do Google Apps Script (Back-end)

Para que o app funcione, abra seu Google Sheets, vá em **Extensões > Apps Script** e substitua todo o código existente por este abaixo. Salve e **Implante como Aplicativo Web** (acesso: qualquer pessoa).

```javascript
// CÓDIGO DO GOOGLE APPS SCRIPT (.gs)
const SS = SpreadsheetApp.getActiveSpreadsheet();
const SHEETS = {
  SHIPMENTS: SS.getSheetByName('Shipments') || SS.insertSheet('Shipments'),
  USERS: SS.getSheetByName('Users') || SS.insertSheet('Users')
};

// Inicializa cabeçalhos se as planilhas forem novas
function setup() {
  if (SHEETS.SHIPMENTS.getLastRow() === 0) {
    SHEETS.SHIPMENTS.appendRow(['id', 'number', 'sendDate', 'quantitySent', 'status', 'returns']);
  }
  if (SHEETS.USERS.getLastRow() === 0) {
    SHEETS.USERS.appendRow(['username', 'password']);
    SHEETS.USERS.appendRow(['Administrador', '1234']); // Usuário padrão
  }
}

function doGet(e) {
  setup();
  const action = e.parameter.action;

  if (action === 'getUsers') {
    const data = SHEETS.USERS.getDataRange().getValues();
    const users = data.slice(1).map(r => ({ username: r[0], password: r[1] }));
    return ContentService.createTextOutput(JSON.stringify(users)).setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'getShipments') {
    const data = SHEETS.SHIPMENTS.getDataRange().getValues();
    const shipments = data.slice(1).map(r => ({
      id: r[0],
      number: r[1],
      sendDate: r[2],
      quantitySent: Number(r[3]),
      status: r[4],
      returns: r[5] // O front-end fará o JSON.parse disso
    }));
    return ContentService.createTextOutput(JSON.stringify({ shipments })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  setup();
  const data = JSON.parse(e.postData.contents);
  const action = data.action;

  if (action === 'syncShipments') {
    // Limpa apenas os dados das remessas, mantendo o cabeçalho
    const lastRow = SHEETS.SHIPMENTS.getLastRow();
    if (lastRow > 1) {
      SHEETS.SHIPMENTS.getRange(2, 1, lastRow - 1, 6).clearContent();
    }

    // Insere as novas remessas vindas do App
    data.shipments.forEach(s => {
      SHEETS.SHIPMENTS.appendRow([
        s.id,
        s.number,
        s.sendDate,
        s.quantitySent,
        s.status,
        JSON.stringify(s.returns) // Salva o array de retornos como string JSON para não perder dados
      ]);
    });

    return ContentService.createTextOutput("OK").setMimeType(ContentService.MimeType.TEXT);
  }

  if (action === 'register') {
    SHEETS.USERS.appendRow([data.user.username, data.user.password]);
    return ContentService.createTextOutput("OK").setMimeType(ContentService.MimeType.TEXT);
  }

  if (action === 'changePassword') {
    const users = SHEETS.USERS.getDataRange().getValues();
    for(let i = 1; i < users.length; i++) {
      if (users[i][0] === data.user.username) {
        SHEETS.USERS.getRange(i + 1, 2).setValue(data.user.password);
        break;
      }
    }
    return ContentService.createTextOutput("OK").setMimeType(ContentService.MimeType.TEXT);
  }
}
```

### Por que isso resolve o problema?
1.  **Sincronização Serial:** O Apps Script agora usa `JSON.stringify(s.returns)` ao salvar e o Front-end usa `JSON.parse` ao ler. Isso resolve o problema de dados complexos que o Google Sheets não entende nativamente.
2.  **Proteção contra Apagamento:** No `App.tsx`, adicionei o `useRef(isInitialMount)` e uma verificação rigorosa no `useEffect`. Isso garante que o aplicativo **nunca** envie uma lista vazia para o servidor logo após abrir, preservando os dados que já existem na nuvem.
3.  **Campo Status:** O campo `status` agora é explicitamente mapeado na coluna 5 da planilha, impedindo que as remessas voltem para o estado padrão de "Aguardando".

