Com certeza! Para atender a essa solicitação, precisamos de uma alteração no **Google Apps Script** (o código que roda dentro da sua planilha) para que ele gerencie essa segunda aba de histórico, e um ajuste no **App.tsx** para garantir que a validação de Notas Fiscais e a sincronização funcionem perfeitamente.

### Especificações das Mudanças:

1.  **Sincronização Dupla (Back-end):** O código do Apps Script agora limpará e reconstruirá a aba `Historico_retornos` toda vez que houver uma sincronização. Cada item de retorno dentro de cada remessa virá a ser uma linha individual nessa tabela, facilitando relatórios e filtros manuais na planilha.
2.  **Mapeamento de Colunas:** A aba `Historico_retornos` terá colunas claras: Remessa, Data Envio, Nota Fiscal, Data Retorno, Reformados, Consertados, Trocados, Sem Reforma e Bônus Resgatados.
3.  **Correção de Duplicidade (Front-end):** No `App.tsx`, adicionei o mapeamento de todas as Notas Fiscais existentes para que o formulário de retorno possa impedir o cadastro de uma nota que já foi usada em outra remessa.
4.  **Estabilidade do Status:** Garanti que o campo `status` seja enviado e recebido exatamente como definido no Enum (`Aguardando Retorno`, `Retorno Parcial`, `Finalizada`), evitando que as remessas "resetem" visualmente.

---

### 1. Código do Google Apps Script (Atualizado)

Substitua todo o código no seu editor do Google Sheets por este:

```javascript
// NOVO CÓDIGO DO GOOGLE APPS SCRIPT (.gs)
const SS = SpreadsheetApp.getActiveSpreadsheet();
const SHEETS = {
  SHIPMENTS: SS.getSheetByName('Shipments') || SS.insertSheet('Shipments'),
  USERS: SS.getSheetByName('Users') || SS.insertSheet('Users'),
  HISTORY: SS.getSheetByName('Historico_retornos') || SS.insertSheet('Historico_retornos')
};

function setup() {
  if (SHEETS.SHIPMENTS.getLastRow() === 0) {
    SHEETS.SHIPMENTS.appendRow(['id', 'number', 'sendDate', 'quantitySent', 'status', 'returns']);
  }
  if (SHEETS.USERS.getLastRow() === 0) {
    SHEETS.USERS.appendRow(['username', 'password']);
    SHEETS.USERS.appendRow(['Administrador', '1234']);
  }
  if (SHEETS.HISTORY.getLastRow() === 0) {
    SHEETS.HISTORY.appendRow(['Remessa', 'Data Envio', 'Nota Fiscal', 'Data Retorno', 'Reformados', 'Consertados', 'Trocados', 'Sem Reforma', 'Bônus Resgatados']);
  }
}

function doGet(e) {
  setup();
  const action = e.parameter.action;
  if (action === 'getUsers') {
    const data = SHEETS.USERS.getDataRange().getValues();
    const users = data.slice(1).map(r => ({ username: r[0], password: r[1] }));
    return ContentService.createTextOutput(JSON.stringify(users)).setMimeType(ContentService.MimeType.JSON);
  }
  if (action === 'getShipments') {
    const data = SHEETS.SHIPMENTS.getDataRange().getValues();
    const shipments = data.slice(1).map(r => ({
      id: r[0], number: r[1], sendDate: r[2], quantitySent: Number(r[3]), status: r[4], returns: r[5]
    }));
    return ContentService.createTextOutput(JSON.stringify({ shipments })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  setup();
  const data = JSON.parse(e.postData.contents);
  if (data.action === 'syncShipments') {
    // 1. Atualizar aba principal de Remessas
    const lastRowS = SHEETS.SHIPMENTS.getLastRow();
    if (lastRowS > 1) SHEETS.SHIPMENTS.getRange(2, 1, lastRowS - 1, 6).clearContent();

    // 2. Limpar aba de Histórico de Retornos para reconstrução
    const lastRowH = SHEETS.HISTORY.getLastRow();
    if (lastRowH > 1) SHEETS.HISTORY.getRange(2, 1, lastRowH - 1, 9).clearContent();

    data.shipments.forEach(s => {
      // Salva na aba principal
      SHEETS.SHIPMENTS.appendRow([
        s.id, s.number, s.sendDate, s.quantitySent, s.status, JSON.stringify(s.returns)
      ]);

      // Alimenta a aba de Histórico detalhado
      const returns = Array.isArray(s.returns) ? s.returns : (typeof s.returns === 'string' ? JSON.parse(s.returns) : []);
      returns.forEach(r => {
        SHEETS.HISTORY.appendRow([
          s.number,
          s.sendDate,
          r.invoiceNumber,
          r.date,
          r.reformed,
          r.repaired,
          r.exchanged,
          r.failed,
          r.bonusesRedeemed || 0
        ]);
      });
    });
    return ContentService.createTextOutput("OK").setMimeType(ContentService.MimeType.TEXT);
  }
  // ... outras ações de login/password ...
}
```

